window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
window.bibleReaderData.chapters['MRK'] = window.bibleReaderData.chapters['MRK'] || {};
(function(chapters){ for (const c in chapters){ window.bibleReaderData.chapters['MRK'][c]=window.bibleReaderData.chapters['MRK'][c]||{}; Object.assign(window.bibleReaderData.chapters['MRK'][c], chapters[c]); } })({"1":{"fa":[{"v":1,"t":"ابتدا انجیل عیسی مسیح پسر خدا."},{"v":2,"t":"چنانکه در اشعیا نبی مکتوب است، «اینک رسول خود را پیش روی تو می‌فرستم تاراه تو را پیش تو مهیا سازد."},{"v":3,"t":"صدای ندا کننده‌ای در بیابان که راه خداوند را مهیا سازید و طرق او راراست نمایید.»"},{"v":4,"t":"یحیی تعمید‌دهنده در بیابان ظاهر شد وبجهت آمرزش گناهان به تعمید توبه موعظه می‌نمود."},{"v":5,"t":"و تمامی مرز و بوم یهودیه و جمیع سکنه اورشلیم نزد وی بیرون شدند و به گناهان خود معترف گردیده، در رود اردون از او تعمیدمی یافتند."},{"v":6,"t":"و یحیی را لباس از پشم شتر وکمربند چرمی بر کمر می‌بود و خوراک وی ازملخ و عسل بری."},{"v":7,"t":"و موعظه می‌کرد و می‌گفت که «بعد از من کسی تواناتر از من می‌آید که لایق آن نیستم که خم شده، دوال نعلین او را باز کنم."},{"v":8,"t":"من شما را به آب تعمید دادم. لیکن او شما را به روح‌القدس تعمید خواهد داد.»"},{"v":9,"t":"و واقع شد در آن ایام که عیسی از ناصره جلیل آمده در اردن از یحیی تعمید یافت."},{"v":10,"t":"وچون از آب برآمد، در ساعت آسمان را شکافته دید و روح را که مانند کبوتری بروی نازل می‌شود."},{"v":11,"t":"و آوازی از آسمان در‌رسید که «توپسر حبیب من هستی که از تو خشنودم.»"},{"v":12,"t":"پس بی‌درنگ روح وی را به بیابان می‌برد."},{"v":13,"t":"و مدت چهل روز در صحرا بود و شیطان او راتجربه می‌کرد و با وحوش بسر می‌برد و فرشتگان او را پرستاری می‌نمودند."},{"v":14,"t":"و بعد از گرفتاری یحیی، عیسی به جلیل آمده، به بشارت ملکوت خدا موعظه کرده،"},{"v":15,"t":"می گفت: «وقت تمام شد و ملکوت خدانزدیک است. پس توبه کنید و به انجیل ایمان بیاورید.»"},{"v":16,"t":"و چون به کناره دریای جلیل می‌گشت، شمعون و برادرش اندریاس را دید که دامی دردریا می‌اندازند زیرا که صیاد بودند."},{"v":17,"t":"عیسی ایشان را گفت: «از عقب من آیید که شما را صیادمردم گردانم.»"},{"v":18,"t":"بی‌تامل دامهای خود را گذارده، از پی او روانه شدند."},{"v":19,"t":"و از آنجا قدری پیشتررفته، یعقوب بن زبدی و برادرش یوحنا را دید که در کشتی دامهای خود را اصلاح می‌کنند."},{"v":20,"t":"درحال ایشان را دعوت نمود. پس پدر خود زبدی را با مزدوران در کشتی گذارده، از عقب وی روانه شدند."},{"v":21,"t":"و چون وارد کفرناحوم شدند، بی‌تامل درروز سبت به کنیسه درآمده، به تعلیم دادن شروع کرد،"},{"v":22,"t":"به قسمی که از تعلیم وی حیران شدند، زیرا که ایشان را مقتدرانه تعلیم می‌داد نه مانندکاتبان."},{"v":23,"t":"و در کنیسه ایشان شخصی بود که روح پلیدداشت. ناگاه صیحه زده،"},{"v":24,"t":"گفت: «ای عیسی ناصری ما را با تو چه‌کار است؟ آیا برای هلاک کردن ما آمدی؟ تو را می‌شناسم کیستی، ای قدوس خدا!»"},{"v":25,"t":"عیسی به وی نهیب داده، گفت: «خاموش شو و از او درآی!»"},{"v":26,"t":"در ساعت آن روح خبیث او را مصروع نمود و به آواز بلند صدازده، از او بیرون آمد."},{"v":27,"t":"و همه متعجب شدند، بحدی که از همدیگر سوال کرده، گفتند: «این چیست و این چه تعلیم تازه است که ارواح پلید رانیز با قدرت امر می‌کند و اطاعتش می‌نمایند؟»"},{"v":28,"t":"و اسم او فور در تمامی مرز و بوم جلیل شهرت یافت."},{"v":29,"t":"و از کنیسه بیرون آمده، فور با یعقوب ویوحنا به خانه شمعون و اندریاس درآمدند."},{"v":30,"t":"ومادر‌زن شمعون تب کرده، خوابیده بود. درساعت وی را از حالت او خبر دادند."},{"v":31,"t":"پس نزدیک شده، دست او را گرفته، برخیزانیدش که همان وقت تب از او زایل شد و به خدمت گذاری ایشان مشغول گشت."},{"v":32,"t":"شامگاه چون آفتاب به مغرب شد، جمیع مریضان و مجانین را پیش او آوردند."},{"v":33,"t":"و تمام شهر بر در خانه ازدحام نمودند."},{"v":34,"t":"و بسا کسانی را که به انواع امراض مبتلا بودند، شفا داد ودیوهای بسیاری بیرون کرده، نگذارد که دیوهاحرف زنند زیرا که او را شناختند."},{"v":35,"t":"بامدادان قبل از صبح برخاسته، بیرون رفت و به ویرانه‌ای رسیده، در آنجا به دعا مشغول شد."},{"v":36,"t":"و شمعون و رفقایش در‌پی او شتافتند."},{"v":37,"t":"چون او را دریافتند، گفتند: «همه تو رامی طلبند.»"},{"v":38,"t":"بدیشان گفت: «به دهات مجاورهم برویم تا در آنها نیز موعظه کنم، زیرا که بجهت این کار بیرون آمدم.»"},{"v":39,"t":"پس در تمام جلیل درکنایس ایشان وعظ می‌نمود و دیوها را اخراج می‌کرد."},{"v":40,"t":"و ابرصی پیش وی آمده، استدعا کرد وزانو زده، بدو گفت: «اگر بخواهی، می‌توانی مراطاهر سازی!»"},{"v":41,"t":"عیسی ترحم نموده، دست خودرا دراز کرد و او را لمس نموده، گفت: «می‌خواهم. طاهر شو!»"},{"v":42,"t":"و چون سخن گفت، فی الفور برص از او زایل شده، پاک گشت."},{"v":43,"t":"و اورا قدغن کرد و فور مرخص فرموده،"},{"v":44,"t":"گفت: «زنهار کسی را خبر مده، بلکه رفته خود را به کاهن بنما و آنچه موسی فرموده، بجهت تطهیر خودبگذران تا برای ایشان شهادتی بشود.»"},{"v":45,"t":"لیکن اوبیرون رفته، به موعظه نمودن و شهرت دادن این امر شروع کرد، بقسمی که بعد از آن او نتوانست آشکارا به شهر درآید بلکه در ویرانه های بیرون بسر می‌برد و مردم از همه اطراف نزد وی می‌آمدند."}]},"2":{"fa":[{"v":1,"t":"و بعد از چندی، باز وارد کفرناحوم شده، چون شهرت یافت که در خانه است،"},{"v":2,"t":"بی درنگ جمعی ازدحام نمودند بقسمی که بیرون در نیز گنجایش نداشت و برای ایشان کلام را بیان می‌کرد."},{"v":3,"t":"که ناگاه بعضی نزد وی آمده مفلوجی را به‌دست چهار نفر برداشته، آوردند."},{"v":4,"t":"و چون به‌سبب جمعیت نتوانستند نزد او برسند، طاق جایی را که او بود باز کرده و شکافته، تختی را که مفلوج بر آن خوابیده بود، به زیر هشتند."},{"v":5,"t":"عیسی چون ایمان ایشان را دید، مفلوج را گفت: «ای فرزند، گناهان تو آمرزیده شد.»"},{"v":6,"t":"لیکن بعضی از کاتبان که در آنجا نشسته بودند، در دل خود تفکر نمودند"},{"v":7,"t":"که «چرا این شخص چنین کفر می‌گوید؟ غیر از خدای واحد، کیست که بتواند گناهان را بیامرزد؟»"},{"v":8,"t":"در ساعت عیسی در روح خود ادراک نموده که با خود چنین فکر می‌کنند، بدیشان گفت: «از بهر‌چه این خیالات را به‌خاطر خود راه می‌دهید؟"},{"v":9,"t":"کدام سهل تر است؟ مفلوج را گفتن گناهان تو آمرزیده شد؟ یا گفتن برخیز و بستر خود را برداشته بخرام؟"},{"v":10,"t":"لیکن تا بدانید که پسر انسان رااستطاعت آمرزیدن گناهان بر روی زمین هست...» مفلوج را گفت:"},{"v":11,"t":"«تو را می‌گویم برخیز و بستر خود را برداشته، به خانه خود برو!»"},{"v":12,"t":"او برخاست و بی‌تامل بستر خود را برداشته، پیش روی همه روانه شد بطوری که همه حیران شده، خدا را تمجید نموده، گفتند: «مثل این امرهرگز ندیده بودیم!»"},{"v":13,"t":"و باز به کناره دریا رفت و تمام آن گروه نزداو آمدند و ایشان را تعلیم می‌داد."},{"v":14,"t":"و هنگامی که می‌رفت لاوی ابن حلفی را بر باجگاه نشسته دید. بدو گفت: «از عقب من بیا!» پس برخاسته، درعقب وی شتافت."},{"v":15,"t":"و وقتی که او در خانه وی نشسته بود، بسیاری از باجگیران و گناهکاران باعیسی و شاگردانش نشستند زیرا بسیار بودند وپیروی او می‌کردند."},{"v":16,"t":"و چون کاتبان و فریسیان او را دیدند که با باجگیران و گناهکاران می‌خورد، به شاگردان او گفتند: «چرا با باجگیران وگناهکاران اکل و شرب می‌نماید؟»"},{"v":17,"t":"عیسی چون این را شنید، بدیشان گفت: «تندرستان احتیاج به طبیب ندارند بلکه مریضان. و من نیامدم تا عادلان را بلکه تا گناهکاران را به توبه دعوت کنم.»"},{"v":18,"t":"و شاگردان یحیی و فریسیان روزه می‌داشتند. پس آمده، بدو گفتند: «چون است که شاگردان یحیی و فریسیان روزه می‌دارند وشاگردان تو روزه نمی دارند؟»"},{"v":19,"t":"عیسی بدیشان گفت: «آیا ممکن است پسران خانه عروسی مادامی که داماد با ایشان است روزه بدارند؟ زمانی که داماد را با خود دارند، نمی توانند روزه‌دارند."},{"v":20,"t":"لیکن ایامی می‌آید که داماد از ایشان گرفته شود. در آن ایام روزه خواهند داشت."},{"v":21,"t":"وهیچ‌کس بر جامه کهنه، پاره‌ای از پارچه نو وصله نمی کند، والا آن وصله نو از آن کهنه جدامی گردد و دریدگی بدتر می‌شود."},{"v":22,"t":"و کسی شراب نو را در مشکهای کهنه نمی ریزد وگرنه آن شراب نو مشکها را بدرد و شراب ریخته، مشکهاتلف می‌گردد. بلکه شراب نو را در مشکهای نوباید ریخت.»"},{"v":23,"t":"و چنان افتاد که روز سبتی از میان مزرعه‌ها می‌گذشت و شاگردانش هنگامی که می‌رفتند، به چیدن خوشه‌ها شروع کردند."},{"v":24,"t":"فریسیان بدو گفتند: «اینک چرا در روزسبت مرتکب عملی می‌باشند که روا نیست؟»"},{"v":25,"t":"او بدیشان گفت: «مگر هرگز نخوانده ایدکه داود چه کرد چون او و رفقایش محتاج وگرسنه بودند؟"},{"v":26,"t":"چگونه در ایام ابیتار رئیس کهنه به خانه خدا درآمده، نان تقدمه راخورد که خوردن آن جز به کاهنان روا نیست و به رفقای خود نیز داد؟»"},{"v":27,"t":"و بدیشان گفت: «سبت بجهت انسان مقرر شد نه انسان برای سبت."},{"v":28,"t":"بنابراین پسر انسان مالک سبت نیزهست.»"}]},"3":{"fa":[{"v":1,"t":"و باز به کنیسه درآمده، در آنجا مرد دست خشکی بود."},{"v":2,"t":"و مراقب وی بودند که شاید او را در سبت شفا دهد تا مدعی او گردند."},{"v":3,"t":"پس بدان مرد دست خشک گفت: «در میان بایست!»"},{"v":4,"t":"و بدیشان گفت: «آیا در روز سبت کدام جایز است؟ نیکویی‌کردن یا بدی؟ جان رانجات دادن یا هلاک کردن؟» ایشان خاموش ماندند."},{"v":5,"t":"پس چشمان خود را بر ایشان باغضب گردانیده، زیرا که از سنگدلی ایشان محزون بود، به آن مرد گفت: «دست خود رادراز کن!» پس دراز کرده، دستش صحیح گشت."},{"v":6,"t":"در ساعت فریسیان بیرون رفته، با هیرودیان درباره او شورا نمودند که چطور او را هلاک کنند."},{"v":7,"t":"و عیسی با شاگردانش به سوی دریا آمد وگروهی بسیار از جلیل به عقب او روانه شدند،"},{"v":8,"t":"واز یهودیه و از اورشلیم و ادومیه و آن طرف اردن و از حوالی صور و صیدون نیز جمعی کثیر، چون اعمال او را شنیدند، نزد وی آمدند."},{"v":9,"t":"و به شاگردان خود فرمود تا زورقی به‌سبب جمعیت، بجهت او نگاه دارند تا بر وی ازدحام ننمایند،"},{"v":10,"t":"زیرا که بسیاری را صحت می‌داد، بقسمی که هر‌که صاحب دردی بود بر او هجوم می‌آورد تااو را لمس نماید."},{"v":11,"t":"و ارواح پلید چون او رادیدند، پیش او به روی در‌افتادند و فریادکنان می‌گفتند که «تو پسر خدا هستی.»"},{"v":12,"t":"و ایشان را به تاکید بسیار فرمود که او را شهرت ندهند."},{"v":13,"t":"پس بر فراز کوهی برآمده، هر‌که راخواست به نزد خود طلبید و ایشان نزد او آمدند."},{"v":14,"t":"و دوازده نفر را مقرر فرمود تا همراه او باشند وتا ایشان را بجهت وعظ نمودن بفرستد،"},{"v":15,"t":"وایشان را قدرت باشد که مریضان را شفا دهند ودیوها را بیرون کنند."},{"v":16,"t":"و شمعون را پطرس نام نهاد."},{"v":17,"t":"و یعقوب پسر زبدی و یوحنا برادریعقوب؛ این هر دو را بوانرجس یعنی پسران رعد نام گذارد."},{"v":18,"t":"و اندریاس و فیلپس و برتولما و متی و توما و یعقوب بن حلفی و تدی وشمعون قانوی،"},{"v":19,"t":"و یهودای اسخریوطی که او راتسلیم کرد."},{"v":20,"t":"و چون به خانه درآمدند، باز جمعی فراهم آمدند بطوری که ایشان فرصت نان خوردن هم نکردند."},{"v":21,"t":"و خویشان او چون شنیدند، بیرون آمدند تا او را بردارند زیرا گفتند بی‌خود شده است."},{"v":22,"t":"و کاتبانی که از اورشلیم آمده بودند، گفتند که بعلزبول دارد و به یاری رئیس دیوها، دیوها را اخراج می‌کند."},{"v":23,"t":"پس ایشان را پیش طلبیده، مثلها زده، بدیشان گفت: «چطور می‌تواندشیطان، شیطان را بیرون کند؟"},{"v":24,"t":"و اگر مملکتی برخلاف خود منقسم شود، آن مملکت نتواندپایدار بماند."},{"v":25,"t":"و هرگاه خانه‌ای به ضد خویش منقسم شد، آن خانه نمی تواند استقامت داشته باشد."},{"v":26,"t":"و اگر شیطان با نفس خود مقاومت نمایدو منقسم شود، او نمی تواند قائم ماند بلکه هلاک می‌گردد."},{"v":27,"t":"و هیچ‌کس نمی تواند به خانه مردزورآور درآمده، اسباب او را غارت نماید، جزآنکه اول آن زورآور را ببندد و بعد از آن خانه اورا تاراج می‌کند."},{"v":28,"t":"هرآینه به شما می‌گویم که همه گناهان از بنی آدم آمرزیده می‌شود و هر قسم کفر که گفته باشند،"},{"v":29,"t":"لیکن هر‌که به روح‌القدس کفر گوید، تا به ابد آمرزیده نشود بلکه مستحق عذاب جاودانی بود.»"},{"v":30,"t":"زیرا که می‌گفتند روحی پلید دارد."},{"v":31,"t":"پس برادران و مادر او آمدند و بیرون ایستاده، فرستادند تا او را طلب کنند."},{"v":32,"t":"آنگاه جماعت گرد او نشسته بودند و به وی گفتند: «اینک مادرت و برادرانت بیرون تو را می‌طلبند.»"},{"v":33,"t":"در جواب ایشان گفت: «کیست مادر من وبرادرانم کیانند؟»"},{"v":34,"t":"پس بر آنانی که گرد وی نشسته بودند، نظر افکنده، گفت: «اینانند مادر وبرادرانم،"},{"v":35,"t":"زیرا هر‌که اراده خدا را به‌جا آردهمان برادر و خواهر و مادر من باشد.»"}]},"4":{"fa":[{"v":1,"t":"و باز به کناره دریا به تعلیم دادن شروع کردو جمعی کثیر نزد او جمع شدند بطوری که به کشتی سوار شده، بر دریا قرار گرفت و تمامی آن جماعت بر ساحل دریا حاضر بودند."},{"v":2,"t":"پس ایشان را به مثلها چیزهای بسیار می‌آموخت و درتعلیم خود بدیشان گفت:"},{"v":3,"t":"«گوش گیرید! اینک برزگری بجهت تخم پاشی بیرون رفت."},{"v":4,"t":"و چون تخم می‌پاشید، قدری بر راه ریخته شده، مرغان هوا آمده آنها را برچیدند."},{"v":5,"t":"و پاره‌ای بر سنگلاخ پاشیده شد، در جایی که خاک بسیار نبود. پس چون که زمین عمق نداشت به زودی رویید،"},{"v":6,"t":"وچون آفتاب برآمد، سوخته شد و از آنرو که ریشه نداشت خشکید."},{"v":7,"t":"و قدری در میان خارها ریخته شد و خارها نمو کرده، آن را خفه نمود که ثمری نیاورد."},{"v":8,"t":"و مابقی در زمین نیکو افتاد و حاصل پیدا نمود که رویید و نمو کرد و بارآورد، بعضی سی وبعضی شصت و بعضی صد.»"},{"v":9,"t":"پس گفت: «هر‌که گوش شنوا دارد، بشنود!»"},{"v":10,"t":"و چون به خلوت شد، رفقای او با آن دوازده شرح این مثل را از او پرسیدند."},{"v":11,"t":"به ایشان گفت: «به شما دانستن سر ملکوت خدا عطاشده، اما به آنانی که بیرونند، همه‌چیز به مثلهامی شود،"},{"v":12,"t":"تا نگران شده بنگرند و نبینند و شنواشده بشنوند و نفهمند، مبادا بازگشت کرده گناهان ایشان آمرزیده شود.»"},{"v":13,"t":"و بدیشان گفت: «آیا این مثل رانفهمیده‌اید؟ پس چگونه سایر مثلها را خواهیدفهمید؟"},{"v":14,"t":"برزگر کلام را می‌کارد."},{"v":15,"t":"و اینانند به کناره راه، جایی که کلام کاشته می‌شود؛ و چون شنیدند فور شیطان آمده کلام کاشته شده درقلوب ایشان را می‌رباید."},{"v":16,"t":"و ایض کاشته شده درسنگلاخ، کسانی می‌باشند که چون کلام رابشنوند، در حال آن را به خوشی قبول کنند،"},{"v":17,"t":"ولکن ریشه‌ای در خود ندارند بلکه فانی می‌باشند؛ و چون صدمه‌ای یا زحمتی به‌سبب کلام روی دهد در ساعت لغزش می‌خورند."},{"v":18,"t":"و کاشته شده در خارها آنانی می‌باشند که چون کلام راشنوند،"},{"v":19,"t":"اندیشه های دنیوی و غرور دولت وهوس چیزهای دیگر داخل شده، کلام را خفه می‌کند و بی‌ثمر می‌گردد."},{"v":20,"t":"و کاشته شده درزمین نیکو آنانند که چون کلام را شنوند آن رامی پذیرند و ثمر می‌آورند، بعضی سی و بعضی شصت و بعضی صد.»"},{"v":21,"t":"پس بدیشان گفت: «آیا چراغ را می‌آورند تازیر پیمانه‌ای یا تختی و نه بر چراغدان گذارند؟"},{"v":22,"t":"زیرا که چیزی پنهان نیست که آشکارا نگردد وهیچ‌چیز مخفی نشود، مگر تا به ظهور آید."},{"v":23,"t":"هرکه گوش شنوا دارد بشنود.»"},{"v":24,"t":"و بدیشان گفت: «باحذر باشید که چه می‌شنوید، زیرا به هر میزانی که وزن کنید به شما پیموده شود، بلکه از برای شماکه می‌شنوید افزون خواهد گشت."},{"v":25,"t":"زیرا هر‌که دارد بدو داده شود و از هر‌که ندارد آنچه نیز داردگرفته خواهد شد.»"},{"v":26,"t":"و گفت: «همچنین ملکوت خدا مانند کسی است که تخم بر زمین بیفشاند،"},{"v":27,"t":"و شب و روزبخوابد و برخیزد و تخم بروید و نمو کند. چگونه؟ او نداند."},{"v":28,"t":"زیرا که زمین به ذات خودثمر می‌آورد، اول علف، بعد خوشه، پس از آن دانه کامل در خوشه."},{"v":29,"t":"و چون ثمر رسید، فور داس را بکار می‌برد زیرا که وقت حصاد رسیده است.»"},{"v":30,"t":"و گفت: «به چه چیز ملکوت خدا را تشبیه کنیم و برای آن چه مثل بزنیم؟"},{"v":31,"t":"مثل دانه خردلی است که وقتی که آن را بر زمین کارند، کوچکترین تخمهای زمینی باشد."},{"v":32,"t":"لیکن چون کاشته شد، می‌روید و بزرگتر از جمیع بقول می‌گردد و شاخه های بزرگ می‌آورد، چنانکه مرغان هوا زیر سایه‌اش می‌توانند آشیانه گیرند.»"},{"v":33,"t":"و به مثلهای بسیار مانند اینهابقدری که استطاعت شنیدن داشتند، کلام رابدیشان بیان می‌فرمود،"},{"v":34,"t":"و بدون مثل بدیشان سخن نگفت. لیکن در خلوت، تمام معانی را برای شاگردان خود شرح می‌نمود."},{"v":35,"t":"و در همان روز وقت شام، بدیشان گفت: «به کناره دیگر عبور کنیم.»"},{"v":36,"t":"پس چون آن گروه رارخصت دادند، او را همانطوری که در کشتی بودبرداشتند و چند زورق دیگر نیز همراه او بود."},{"v":37,"t":"که ناگاه طوفانی عظیم از باد پدید آمد وامواج بر کشتی می‌خورد بقسمی که برمی گشت."},{"v":38,"t":"و او در موخر کشتی بر بالشی خفته بود. پس اورا بیدار کرده گفتند: «ای استاد، آیا تو را باکی نیست که هلاک شویم؟»"},{"v":39,"t":"در ساعت اوبرخاسته، باد را نهیب داد و به دریا گفت: «ساکن شو و خاموش باش!» که باد ساکن شده، آرامی کامل پدید آمد."},{"v":40,"t":"و ایشان را گفت: «از بهر‌چه چنین ترسانید و چون است که ایمان ندارید؟»"},{"v":41,"t":"پس بی‌نهایت ترسان شده، به یکدیگر گفتند: «این کیست که باد و دریا هم او را اطاعت می‌کنند؟»"}]},"5":{"fa":[{"v":1,"t":"پس به آن کناره دریا تا به‌سرزمین جدریان آمدند."},{"v":2,"t":"و چون از کشتی بیرون آمد، فی الفور شخصی که روحی پلید داشت از قبوربیرون شده، بدو برخورد."},{"v":3,"t":"که در قبور ساکن می‌بود و هیچ‌کس به زنجیرها هم نمی توانست اورا بند نماید،"},{"v":4,"t":"زیرا که بارها او را به کنده‌ها وزنجیرها بسته بودند و زنجیرها را گسیخته وکنده‌ها را شکسته بود و احدی نمی توانست او رارام نماید،"},{"v":5,"t":"و پیوسته شب وروز در کوهها وقبرها فریا می‌زد و خود را به سنگها مجروح می‌ساخت."},{"v":6,"t":"چون عیسی را از دور دید، دوان دوان آمده، او را سجده کرد،"},{"v":7,"t":"و به آواز بلندصیحه زده، گفت: «ای عیسی، پسر خدای تعالی، مرا با تو چه‌کار است؟ تو را به خدا قسم می‌دهم که مرا معذب نسازی.»"},{"v":8,"t":"زیرا بدو گفته بود: «ای روح پلید از این شخص بیرون بیا!»"},{"v":9,"t":"پس از اوپرسید: «اسم تو چیست؟» «به وی گفت: «نام من لجئون است زیرا که بسیاریم.»"},{"v":10,"t":"پس بدوالتماس بسیار نمود که ایشان را از آن سرزمین بیرون نکند."},{"v":11,"t":"و در حوالی آن کوهها، گله گرازبسیاری می‌چرید."},{"v":12,"t":"و همه دیوها از وی خواهش نموده، گفتند: «ما را به گرازها بفرست تادر آنها داخل شویم.»"},{"v":13,"t":"فور عیسی ایشان رااجازت داد. پس آن ارواح خبیث بیرون شده، به گرازان داخل گشتند و آن گله از بلندی به دریاجست و قریب بدو هزار بودند که در آب خفه شدند."},{"v":14,"t":"و خوک با نان فرار کرده، در شهر ومزرعه‌ها خبر می‌دادند و مردم بجهت دیدن آن ماجرا بیرون شتافتند."},{"v":15,"t":"و چون نزد عیسی رسیده، آن دیوانه را که لجئون داشته بود دیدند که نشسته و لباس پوشیده و عاقل گشته است، بترسیدند."},{"v":16,"t":"و آنانی که دیده بودند، سرگذشت دیوانه و گرازان را بدیشان بازگفتند."},{"v":17,"t":"پس شروع به التماس نمودند که از حدود ایشان روانه شود."},{"v":18,"t":"و چون به کشتی سوار شد، آنکه دیوانه بود ازوی استدعا نمود که با وی باشد."},{"v":19,"t":"اما عیسی وی را اجازت نداد بلکه بدو گفت: «به خانه نزدخویشان خود برو و ایشان را خبر ده از آنچه خداوند با تو کرده است و چگونه به تو رحم نموده است.»"},{"v":20,"t":"پس روانه شده، در دیکاپولس به آنچه عیسی با وی کرده، موعظه کردن آغاز نمودکه همه مردم متعجب شدند."},{"v":21,"t":"و چون عیسی باز به آنطرف، در کشتی عبور نمود، مردم بسیار بر وی جمع گشتند و برکناره دریا بود."},{"v":22,"t":"که ناگاه یکی از روسای کنیسه، یایرس نام آمد و چون او را بدید بر پایهایش افتاده،"},{"v":23,"t":"بدو التماس بسیار نموده، گفت: «نفس دخترک من به آخر رسیده. بیا و بر او دست گذار تاشفا یافته، زیست کند.»"},{"v":24,"t":"پس با او روانه شده، خلق بسیاری نیز از پی او افتاده، بر وی ازدحام می‌نمودند."},{"v":25,"t":"آنگاه زنی که مدت دوازده سال به استحاضه مبتلا می‌بود،"},{"v":26,"t":"و زحمت بسیار ازاطبای متعدد دیده و آنچه داشت صرف نموده، فایده‌ای نیافت بلکه بدتر می‌شد،"},{"v":27,"t":"چون خبرعیسی را بشنید، میان آن گروه از عقب وی آمده ردای او را لمس نمود،"},{"v":28,"t":"زیرا گفته بود: «اگرلباس وی را هم لمس کنم، هرآینه شفا یابم.»"},{"v":29,"t":"در ساعت چشمه خون او خشک شده، در تن خود فهمید که از آن بلا صحت یافته است."},{"v":30,"t":"فی الفور عیسی از خود دانست که قوتی از اوصادر گشته. پس در آن جماعت روی برگردانیده، گفت: «کیست که لباس مرا لمس نمود؟»"},{"v":31,"t":"شاگردانش بدو گفتند: «می‌بینی که مردم بر توازدحام می‌نمایند! و می‌گویی کیست که مرا لمس نمود؟ !»"},{"v":32,"t":"پس به اطراف خود می‌نگریست تا آن زن را که این کار کرده، ببیند."},{"v":33,"t":"آن زن چون دانست که به وی چه واقع شده، ترسان و لرزان آمد و نزد او به روی در‌افتاده، حقیقت امر رابالتمام به وی باز‌گفت."},{"v":34,"t":"او وی را گفت: «ای دختر، ایمانت تو را شفا داده است. به سلامتی بروو از بلای خویش رستگار باش.»"},{"v":35,"t":"او هنوز سخن می‌گفت که بعضی از خانه رئیس کنیسه آمده، گفتند: «دخترت فوت شده؛ دیگر برای چه استاد را زحمت می‌دهی؟»"},{"v":36,"t":"عیسی چون سخنی را که گفته بودند شنید، درساعت به رئیس کنیسه گفت: «مترس ایمان آور وبس!»"},{"v":37,"t":"و جز پطرس و یعقوب و یوحنا برادریعقوب، هیچ‌کس را اجازت نداد که از عقب اوبیایند."},{"v":38,"t":"پس چون به خانه رئیس کنیسه رسیدند، جمعی شوریده دید که گریه و نوحه بسیار می‌نمودند."},{"v":39,"t":"پس داخل شده، بدیشان گفت: «چرا غوغا و گریه می‌کنید؟ دختر نمرده بلکه در خواب است.»"},{"v":40,"t":"ایشان بر وی سخریه کردند لیکن او همه را بیرون کرده، پدر و مادردختر را با رفیقان خویش برداشته، به‌جایی که دختر خوابیده بود، داخل شد."},{"v":41,"t":"پس دست دختر را گرفته، به وی گفت: «طلیتا قومی.» که معنی آن این است: «ای دختر، تو را می‌گویم برخیز.»"},{"v":42,"t":"در ساعت دختر برخاسته، خرامید زیرا که دوازده ساله بود. ایشان بینهایت متعجب شدند."},{"v":43,"t":"پس ایشان را به تاکید بسیار فرمود: «کسی از این امر مطلع نشود.» و گفت تا خوراکی بدو دهند."}]},"6":{"fa":[{"v":1,"t":"پس از آنجا روانه شده، به وطن خویش آمد و شاگردانش از عقب او آمدند."},{"v":2,"t":"چون روز سبت رسید، در کنیسه تعلیم دادن آغاز نمودو بسیاری چون شنیدند، حیران شده گفتند: «ازکجا بدین شخص این چیزها رسیده و این چه حکمت است که به او عطا شده است که چنین معجزات از دست او صادر می‌گردد؟"},{"v":3,"t":"مگر این نیست نجار پسر مریم و برادر یعقوب و یوشا ویهودا و شمعون؟ و خواهران او اینجا نزد مانمی باشند؟» و از او لغزش خوردند."},{"v":4,"t":"عیسی ایشان را گفت: «نبی بی‌حرمت نباشد جز در وطن خود و میان خویشان و در خانه خود."},{"v":5,"t":"و در آنجاهیچ معجزه‌ای نتوانست نمود جز اینکه دستهای خود را بر چند مریض نهاده، ایشان را شفا داد."},{"v":6,"t":"واز بی‌ایمانی‌ایشان متعجب شده، در دهات آن حوالی گشته، تعلیم همی داد."},{"v":7,"t":"پس آن دوازده را پیش خوانده، شروع کرد به فرستادن ایشان جفت جفت و ایشان را بر ارواح پلید قدرت داد،"},{"v":8,"t":"و ایشان را قدغن فرمود که «جزعصا فقط، هیچ‌چیز برندارید، نه توشه‌دان و نه پول در کمربند خود،"},{"v":9,"t":"بلکه موزه‌ای در پا کنید ودو قبا در بر نکنید.»"},{"v":10,"t":"و بدیشان گفت: «در هر جاداخل خانه‌ای شوید، در آن بمانید تا از آنجا کوچ کنید."},{"v":11,"t":"و هرجا که شما را قبول نکنند و به سخن شما گوش نگیرند، از آن مکان بیرون رفته، خاک پایهای خود را بیفشانید تا بر آنها شهادتی گردد. هرآینه به شما می‌گویم حالت سدوم و غموره درروز جزا از آن شهر سهل تر خواهد بود.»"},{"v":12,"t":"پس روانه شده، موعظه کردند که توبه کنند،"},{"v":13,"t":"وبسیار دیوها را بیرون کردند و مریضان کثیر راروغن مالیده، شفا دادند."},{"v":14,"t":"و هیرودیس پادشاه شنید زیرا که اسم اوشهرت یافته بود و گفت که «یحیی تعمید‌دهنده از مردگان برخاسته است و از این جهت معجزات از او به ظهور می‌آید."},{"v":15,"t":"اما بعضی گفتند که الیاس است و بعضی گفتند که نبی‌ای است یا چون یکی از انبیا."},{"v":16,"t":"اما هیرودیس چون شنید گفت: «این همان یحیی است که من سرش را از تن جدا کردم که از مردگان برخاسته است.»"},{"v":17,"t":"زیرا که هیرودیس فرستاده، یحیی را گرفتار نموده، او رادر زندان بست بخاطر هیرودیا، زن برادر او فیلپس که او را در نکاح خویش آورده بود."},{"v":18,"t":"از آن جهت که یحیی به هیرودیس گفته بود: «نگاه داشتن زن برادرت بر تو روا نیست.»"},{"v":19,"t":"پس هیرودیا از او کینه داشته، می‌خواست اور ا به قتل رساند اما نمی توانست،"},{"v":20,"t":"زیرا که هیرودیس از یحیی می‌ترسید چونکه او را مرد عادل و مقدس می‌دانست و رعایتش می‌نمود و هرگاه از اومی شنید بسیار به عمل می‌آورد و به خوشی سخن او را اصغا می‌نمود."},{"v":21,"t":"اما چون هنگام فرصت رسید که هیرودیس در روز میلاد خودامرای خود و سرتیبان و روسای جلیل را ضیافت نمود؛"},{"v":22,"t":"و دختر هیرودیا به مجلس درآمده، رقص کرد و هیرودیس و اهل مجلس را شادنمود. پادشاه بدان دختر گفت: «آنچه خواهی ازمن بطلب تا به تو دهم.»"},{"v":23,"t":"و از برای او قسم خوردکه آنچه از من خواهی حتی نصف ملک مراهرآینه به تو عطا کنم.»"},{"v":24,"t":"او بیرون رفته، به مادرخود گفت: «چه بطلبم؟» گفت: «سر یحیی تعمیددهنده را.»"},{"v":25,"t":"در ساعت به حضور پادشاه درآمده، خواهش نموده، گفت: «می‌خواهم که الان سر یحیی تعمید‌دهنده را در طبقی به من عنایت فرمایی.»"},{"v":26,"t":"پادشاه به شدت محزون گشت، لیکن بجهت پاس قسم و خاطر اهل مجلس نخواست او را محروم نماید."},{"v":27,"t":"بی‌درنگ پادشاه جلادی فرستاده، فرمود تا سرش رابیاورد."},{"v":28,"t":"و او به زندان رفته سر او را از تن جداساخته و بر طبقی آورده، بدان دختر داد و دخترآن را به مادر خود سپرد."},{"v":29,"t":"چون شاگردانش شنیدند، آمدند و بدن او را برداشته، دفن کردند."},{"v":30,"t":"و رسولان نزد عیسی جمع شده، از آنچه کرده و تعلیم داده بودند او را خبر دادند."},{"v":31,"t":"بدیشان گفت شما به خلوت، به‌جای ویران بیایید و اندکی استراحت نمایید زیرا آمد و رفت چنان بود که فرصت نان خوردن نیز نکردند."},{"v":32,"t":"پس به تنهایی در کشتی به موضعی ویران رفتند."},{"v":33,"t":"و مردم ایشان را روانه دیده، بسیاری اورا شناختند و از جمیع شهرها بر خشکی بدان سوشتافتند و از ایشان سبقت جسته، نزد وی جمع شدند."},{"v":34,"t":"عیسی بیرون آمده، گروهی بسیار دیده، بر ایشان ترحم فرمود زیرا که چون گوسفندان بی‌شبان بودند و بسیار به ایشان تعلیم دادن گرفت."},{"v":35,"t":"و چون بیشتری از روز سپری گشت، شاگردانش نزد وی آمده، گفتند: «این مکان ویرانه است و وقت منقضی شده."},{"v":36,"t":"اینها را رخصت ده تا به اراضی و دهات این نواحی رفته، نان بجهت خود بخرند که هیچ خوراکی ندارند.»"},{"v":37,"t":"درجواب ایشان گفت: «شما ایشان را غذا دهید!» وی را گفتند: «مگر رفته، دویست دینار نان بخریم تا اینها را طعام دهیم!»"},{"v":38,"t":"بدیشان گفت: «چند نان دارید؟ رفته، تحقیق کنید.» پس دریافت کرده، گفتند: «پنج نان و دو ماهی.»"},{"v":39,"t":"آنگاه ایشان رافرمود که «همه را دسته دسته بر سبزه بنشانید.»"},{"v":40,"t":"پس صف صف، صد صد و پنجاه پنجاه نشستند."},{"v":41,"t":"و آن پنج نان و دو ماهی را گرفته، به سوی آسمان نگریسته، برکت داد و نان را پاره نموده، به شاگردان خود بسپرد تا پیش آنهابگذارند و آن دو ماهی را بر همه آنها تقسیم نمود."},{"v":42,"t":"پس جمیع خورده، سیر شدند."},{"v":43,"t":"و ازخرده های نان و ماهی، دوازده سبد پر کرده، برداشتند."},{"v":44,"t":"و خورندگان نان، قریب به پنج هزارمرد بودند."},{"v":45,"t":"فی الفور شاگردان خود را الحاح فرمود که به کشتی سوار شده، پیش از او به بیت صیدا عبورکنند تا خود آن جماعت را مرخص فرماید."},{"v":46,"t":"وچون ایشان را مرخص نمود، بجهت عبادت به فراز کوهی برآمد."},{"v":47,"t":"و چون شام شد، کشتی درمیان دریا رسید و او تنها بر خشکی بود."},{"v":48,"t":"وایشان را در راندن کشتی خسته دید زیرا که بادمخالف بر ایشان می‌وزید. پس نزدیک پاس چهارم از شب بر دریا خرامان شده، به نزد ایشان آمد و خواست از ایشان بگذرد."},{"v":49,"t":"اما چون او رابر دریا خرامان دیدند، تصور نمودند که این خیالی است. پس فریاد برآوردند،"},{"v":50,"t":"زیرا که همه او را دیده، مضطرب شدند. پس بی‌درنگ بدیشان خطاب کرده، گفت: «خاطر جمع دارید! من هستم، ترسان مباشید!»"},{"v":51,"t":"و تا نزد ایشان به کشتی سوار شد، باد ساکن گردید چنانکه بینهایت درخود متحیر و متعجب شدند،"},{"v":52,"t":"زیرا که معجزه نان را درک نکرده بودند زیرا دل ایشان سخت بود."},{"v":53,"t":"پس از دریا گذشته، به‌سرزمین جنیسارت آمده، لنگر انداختند."},{"v":54,"t":"و چون از کشتی بیرون شدند، مردم در حال او را شناختند،"},{"v":55,"t":"و در همه آن نواحی بشتاب می‌گشتند و بیماران را بر تختهانهاده، هر جا که می‌شنیدند که او در آنجا است، می‌آوردند."},{"v":56,"t":"و هر جایی که به دهات یا شهرها یا اراضی می‌رفت، مریضان را بر راهها می‌گذاردندو از او خواهش می‌نمودند که محض دامن ردای او را لمس کنند و هر‌که آن را لمس می‌کرد شفامی یافت."}]},"7":{"fa":[{"v":1,"t":"و فریسیان و بعضی کاتبان از اورشلیم آمده، نزد او جمع شدند."},{"v":2,"t":"چون بعضی ازشاگردان او را دیدند که با دستهای ناپاک یعنی ناشسته نان می‌خورند، ملامت نمودند،"},{"v":3,"t":"زیرا که فریسیان و همه یهود تمسک به تقلید مشایخ نموده، تا دستها را بدقت نشویند غذا نمی خورند،"},{"v":4,"t":"و چون از بازارها آیند تا نشویند چیزی نمی خورند و بسیار رسوم دیگر هست که نگاه می‌دارند چون شستن پیاله‌ها و آفتابه‌ها و ظروف مس و کرسیها."},{"v":5,"t":"پس فریسیان و کاتبان از اوپرسیدند: «چون است که شاگردان تو به تقلیدمشایخ سلوک نمی نمایند بلکه به‌دستهای ناپاک نان می‌خورند؟»"},{"v":6,"t":"در جواب ایشان گفت: «نیکو اخبار نموداشعیا درباره شما‌ای ریاکاران، چنانکه مکتوب است: این قوم به لبهای خود مرا حرمت می‌دارندلیکن دلشان از من دور است."},{"v":7,"t":"پس مرا عبث عبادت می‌نمایند زیرا که رسوم انسانی را به‌جای فرایض تعلیم می‌دهند،"},{"v":8,"t":"زیرا حکم خدا را ترک کرده، تقلید انسان را نگاه می‌دارند، چون شستن آفتابه‌ها و پیاله‌ها و چنین رسوم دیگر بسیار بعمل می‌آورید.»"},{"v":9,"t":"پس بدیشان گفت که «حکم خدا رانیکو باطل ساخته‌اید تا تقلید خود را محکم بدارید."},{"v":10,"t":"از اینجهت که موسی گفت پدر و مادرخود را حرمت دار و هر‌که پدر یا مادر را دشنام دهد، البته هلاک گردد."},{"v":11,"t":"لیکن شما می‌گویید که هرگاه شخصی به پدر یا مادر خود گوید: “آنچه ازمن نفع یابی قربان یعنی هدیه برای خداست “"},{"v":12,"t":"وبعد از این او را اجازت نمی دهید که پدر یا مادرخود را هیچ خدمت کند."},{"v":13,"t":"پس کلام خدا را به تقلیدی که خود جاری ساخته‌اید، باطل می‌سازید و کارهای مثل این بسیار به‌جامی آورید.»"},{"v":14,"t":"پس آن جماعت را پیش خوانده، بدیشان گفت: «همه شما به من گوش دهید و فهم کنید."},{"v":15,"t":"هیچ‌چیز نیست که از بیرون آدم داخل او گشته، بتواند او را نجس سازد بلکه آنچه از درونش صادر شود آن است که آدم را ناپاک می‌سازد."},{"v":16,"t":"هر‌که گوش شنوا دارد بشنود.»"},{"v":17,"t":"و چون از نزد جماعت به خانه در‌آمد، شاگردانش معنی مثل را از او پرسیدند."},{"v":18,"t":"بدیشان گفت: «مگر شما نیز همچنین بی‌فهم هستید ونمی دانید که آنچه از بیرون داخل آدم می‌شود، نمی تواند او را ناپاک سازد،"},{"v":19,"t":"زیرا که داخل دلش نمی شود بلکه به شکم می‌رود و خارج می‌شود به مزبله‌ای که این همه خوراک را پاک می‌کند.»"},{"v":20,"t":"وگفت: «آنچه از آدم بیرون آید، آن است که انسان را ناپاک می‌سازد،"},{"v":21,"t":"زیرا که از درون دل انسان صادر می‌شود، خیالات بد و زنا و فسق و قتل ودزدی"},{"v":22,"t":"و طمع و خباثت و مکر و شهوت‌پرستی و چشم بد و کفر و غرور و جهالت."},{"v":23,"t":"تمامی این چیزهای بد از درون صادر می‌گردد و آدم را ناپاک می‌گرداند.»"},{"v":24,"t":"پس از آنجا برخاسته به حوالی صور وصیدون رفته، به خانه درآمد و خواست که هیچ‌کس مطلع نشود، لیکن نتوانست مخفی بماند،"},{"v":25,"t":"از آنرو که زنی که دخترک وی روح پلیدداشت، چون خبر او را بشنید، فور آمده برپایهای او افتاد."},{"v":26,"t":"و او زن یونانی از اهل فینیقیه صوریه بود. پس از وی استدعا نمود که دیو را ازدخترش بیرون کند."},{"v":27,"t":"عیسی وی را گفت: «بگذار اول فرزندان سیر شوند زیرا نان فرزندان راگرفتن و پیش سگان انداختن نیکو نیست.»"},{"v":28,"t":"آن زن در جواب وی گفت: «بلی خداوندا، زیرا سگان نیز پس خرده های فرزندان را از زیر سفره می‌خورند.»"},{"v":29,"t":"وی را گفت؛ «بجهت این سخن برو که دیو از دخترت بیرون شد.»"},{"v":30,"t":"پس چون به خانه خود رفت، دیو را بیرون شده و دختر را بربستر خوابیده یافت."},{"v":31,"t":"و باز از نواحی صور روانه شده، از راه صیدون در میان حدود دیکاپولس به دریای جلیل آمد."},{"v":32,"t":"آنگاه کری را که لکنت زبان داشت نزد وی آورده، التماس کردند که دست بر او گذارد."},{"v":33,"t":"پس او را از میان جماعت به خلوت برده، انگشتان خود را در گوشهای او گذاشت و آب دهان انداخته، زبانش را لمس نمود؛"},{"v":34,"t":"و به سوی آسمان نگریسته، آهی کشید و بدو گفت: «افتح!» یعنی باز شو"},{"v":35,"t":"در ساعت گوشهای او گشاده وعقده زبانش حل شده، به درستی تکلم نمود."},{"v":36,"t":"پس ایشان را قدغن فرمود که هیچ‌کس را خبرندهند؛ لیکن چندان‌که بیشتر ایشان را قدغن نمود، زیادتر او را شهرت دادند."},{"v":37,"t":"و بینهایت متحیر گشته می‌گفتند: «همه کارها را نیکوکرده است؛ کران را شنوا و گنگان را گویامی گرداند!»"}]},"8":{"fa":[{"v":1,"t":"و در آن ایام باز جمعیت، بسیار شده و خوراکی نداشتند. عیسی شاگردان خود راپیش طلبیده، به ایشان گفت:"},{"v":2,"t":"«بر این گروه دلم بسوخت زیرا الان سه روز است که با من می‌باشندو هیچ خوراک ندارند."},{"v":3,"t":"و هرگاه ایشان را گرسنه به خانه های خود برگردانم، هرآینه در راه ضعف کنند، زیرا که بعضی از ایشان از راه دور آمده‌اند.»"},{"v":4,"t":"شاگردانش وی را جواب دادند: «از کجا کسی می‌تواند اینها را در این صحرا از نان سیر گرداند؟»"},{"v":5,"t":"از ایشان پرسید: «چند نان دارید؟» گفتند: «هفت.»"},{"v":6,"t":"پس جماعت را فرمود تا بر زمین بنشینند؛ و آن هفت نان را گرفته، شکر نمود و پاره کرده، به شاگردان خود داد تا پیش مردم گذارند. پس نزد آن گروه نهادند."},{"v":7,"t":"و چند ماهی کوچک نیز داشتند. آنها را نیز برکت داده، فرمود تا پیش ایشان نهند."},{"v":8,"t":"پس خورده، سیر شدند و هفت زنبیل پر از پاره های باقی‌مانده برداشتند."},{"v":9,"t":"و عددخورندگان قریب به چهار هزار بود. پس ایشان رامرخص فرمود."},{"v":10,"t":"و بی‌درنگ با شاگردان به کشتی سوار شده، به نواحی دلمانوته آمد."},{"v":11,"t":"و فریسیان بیرون آمده، با وی به مباحثه شروع کردند. و از راه امتحان آیتی آسمانی از او خواستند."},{"v":12,"t":"او از دل آهی کشیده، گفت: «از برای چه این فرقه آیتی می‌خواهند؟ هرآینه به شما می‌گویم آیتی بدین فرقه عطا نخواهد شد.»"},{"v":13,"t":"پس ایشان را گذارد و باز به کشتی سوارشده، به کناره دیگر عبور نمود."},{"v":14,"t":"و فراموش کردند که نان بردارند و با خود در کشتی جز یک نان نداشتند."},{"v":15,"t":"آنگاه ایشان را قدغن فرمود که «باخبر باشید و از خمیر مایه فریسیان و خمیرمایه هیرودیس احتیاط کنید!»"},{"v":16,"t":"ایشان با خوداندیشیده، گفتند: «از آن است که نان نداریم.»"},{"v":17,"t":"عیسی فهم کرده، بدیشان گفت: «چرا فکرمی کنید از آنجهت که نان ندارید؟ آیا هنوزنفهمیده و درک نکرده‌اید و تا حال دل شما سخت است؟"},{"v":18,"t":"آیا چشم داشته نمی بینید و گوش داشته نمی شنوید و به یاد ندارید؟"},{"v":19,"t":"وقتی که پنج نان را برای پنج هزار نفر پاره کردم، چند سبدپر از پاره‌ها برداشتید؟» بدو گفتند: «دوازده.»"},{"v":20,"t":"«و وقتی که هفت نان را بجهت چهار هزار کس؛ پس زنبیل پر از ریزه‌ها برداشتید؟» گفتندش: «هفت.»"},{"v":21,"t":"پس بدیشان گفت: «چرا نمی فهمید؟»"},{"v":22,"t":"چون به بیت صیدا آمد، شخصی کور را نزد او آوردند و التماس نمودند که او را لمس نماید."},{"v":23,"t":"پس دست آن کور را گرفته، او را از قریه بیرون برد و آب دهان بر چشمان او افکنده، و دست بر اوگذارده از او پرسید که «چیزی می‌بینی؟»"},{"v":24,"t":"اوبالا نگریسته، گفت: «مردمان را خرامان، چون درختها می‌بینم.»"},{"v":25,"t":"پس بار دیگر دستهای خودرا بر چشمان او گذارده، او را فرمود تا بالانگریست و صحیح گشته، همه‌چیز را به خوبی دید."},{"v":26,"t":"پس او را به خانه‌اش فرستاده، گفت: «داخل ده مشو و هیچ‌کس را در آن جا خبر مده.»"},{"v":27,"t":"و عیسی با شاگردان خود به دهات قیصریه فیلپس رفت. و در راه از شاگردانش پرسیده، گفت که «مردم مرا که می‌دانند؟»"},{"v":28,"t":"ایشان جواب دادند که «یحیی تعمید‌دهنده و بعضی الیاس وبعضی یکی از انبیا.»"},{"v":29,"t":"او از ایشان پرسید: «شمامرا که می‌دانید؟» پطرس در جواب او گفت: «تومسیح هستی.»"},{"v":30,"t":"پس ایشان را فرمود که «هیچ‌کس را از او خبر ندهند.»"},{"v":31,"t":"آنگاه ایشان را تعلیم دادن آغاز کرد که «لازم است پسر انسان بسیار زحمت کشد و ازمشایخ و روسای کهنه و کاتبان رد شود و کشته شده، بعد از سه روز برخیزد.»"},{"v":32,"t":"و چون این کلام را علانیه فرمود، پطرس او را گرفته، به منع کردن شروع نمود."},{"v":33,"t":"اما او برگشته، به شاگردان خودنگریسته، پطرس را نهیب داد و گفت: «ای شیطان از من دور شو، زیرا امور الهی را اندیشه نمی کنی بلکه چیزهای انسانی را.»"},{"v":34,"t":"پس مردم را با شاگردان خود خوانده، گفت: «هر‌که خواهد از عقب من آید، خویشتن را انکارکند و صلیب خود را برداشته، مرا متابعت نماید."},{"v":35,"t":"زیرا هر‌که خواهد جان خود را نجات دهد، آن را هلاک سازد؛ و هر‌که جان خود را بجهت من وانجیل بر باد دهد آن را برهاند."},{"v":36,"t":"زیراکه شخص را چه سود دارد هر گاه تمام دنیا را ببرد و نفس خود را ببازد؟"},{"v":37,"t":"یا آنکه آدمی چه چیز را به عوض جان خود بدهد؟"},{"v":38,"t":"زیرا هر‌که در این فرقه زناکار و خطاکار از من و سخنان من شرمنده شود، پسر انسان نیز وقتی که با فرشتگان مقدس درجلال پدر خویش آید، از او شرمنده خواهدگردید.»"}]},"9":{"fa":[{"v":1,"t":"و بدیشان گفت: «هرآینه به شما می‌گویم بعضی از ایستادگان در اینجا می‌باشند که تاملکوت خدا را که به قوت می‌آید نبینند، ذائقه موت را نخواهند چشید.»"},{"v":2,"t":"و بعد از شش روز، عیسی پطرس و یعقوب و یوحنا را برداشته، ایشان را تنها بر فراز کوهی به خلوت برد و هیاتش در نظر ایشان متغیر گشت."},{"v":3,"t":"و لباس او درخشان و چون برف بغایت سفید گردید، چنانکه هیچ گازری بر روی زمین نمی تواند چنان سفید نماید."},{"v":4,"t":"و الیاس با موسی بر ایشان ظاهر شده، با عیسی گفتگو می‌کردند."},{"v":5,"t":"پس پطرس ملتفت شده، به عیسی گفت: «ای استاد، بودن ما در اینجا نیکو است! پس سه سایبان می‌سازیم، یکی برای تو و دیگری برای موسی و سومی برای الیاس!»"},{"v":6,"t":"از آنرو که نمی دانست چه بگوید، چونکه هراسان بودند."},{"v":7,"t":"ناگاه ابری بر ایشان سایه انداخت و آوازی از ابردر‌رسید که «این است پسر حبیب من، از اوبشنوید.»"},{"v":8,"t":"در ساعت گرداگرد خود نگریسته، جزعیسی تنها با خود هیچ‌کس را ندیدند."},{"v":9,"t":"و چون از کوه به زیر می‌آمدند، ایشان راقدغن فرمود که تا پسر انسان از مردگان برنخیزد، از آنچه دیده‌اند کسی را خبر ندهند."},{"v":10,"t":"و این سخن را در خاطر خود نگاه داشته، از یکدیگرسوال می‌کردند که برخاستن از مردگان چه باشد."},{"v":11,"t":"پس از او استفسار کرده، گفتند: «چرا کاتبان می‌گویند که الیاس باید اول بیاید؟»"},{"v":12,"t":"او درجواب ایشان گفت که «الیاس البته اول می‌آید وهمه‌چیز را اصلاح می‌نماید و چگونه درباره پسرانسان مکتوب است که می‌باید زحمت بسیارکشد و حقیر شمرده شود."},{"v":13,"t":"لیکن به شمامی گویم که الیاس هم آمد و با وی آنچه خواستندکردند، چنانچه در حق وی نوشته شده است.»"},{"v":14,"t":"پس چون نزد شاگردان خود رسید، جمعی کثیر گرد ایشان دید و بعضی از کاتبان را که باایشان مباحثه می‌کردند."},{"v":15,"t":"در ساعت، تمامی خلق چون او را بدیدند در حیرت افتادند و دوان دوان آمده، او را سلام دادند."},{"v":16,"t":"آنگاه از کاتبان پرسید که «با اینها چه مباحثه دارید؟»"},{"v":17,"t":"یکی ازآن میان در جواب گفت: «ای استاد، پسر خود رانزد تو آوردم که روحی گنگ دارد،"},{"v":18,"t":"و هر جا که او را بگیرد می‌اندازدش، چنانچه کف برآورده، دندانهایم بهم می‌ساید و خشک می‌گردد. پس شاگردان تو را گفتم که او را بیرون کنند، نتوانستند.»"},{"v":19,"t":"او ایشان را جواب داده، گفت: «ای فرقه بی‌ایمان تا کی با شما باشم و تا چه حدمتحمل شما شوم! او را نزد من آورید.»"},{"v":20,"t":"پس اورا نزد وی آوردند. چون او را دید، فور آن روح او را مصروع کرد تا بر زمین افتاده، کف برآورد وغلطان شد."},{"v":21,"t":"پس از پدر وی پرسید: «چند وقت است که او را این حالت است؟» گفت: «ازطفولیت."},{"v":22,"t":"و بارها او را در آتش و در آب انداخت تا او را هلاک کند. حال اگر می‌توانی بر ماترحم کرده، ما را مدد فرما.»"},{"v":23,"t":"عیسی وی راگفت: «اگر می‌توانی‌ایمان آری، مومن را همه‌چیزممکن است.»"},{"v":24,"t":"در ساعت پدر طفل فریادبرآورده، گریه‌کنان گفت: «ایمان می‌آورم‌ای خداوند، بی‌ایمانی مرا امداد فرما.»"},{"v":25,"t":"چون عیسی دید که گروهی گرد او به شتاب می‌آیند، روح پلید را نهیب داده، به وی فرمود: «ای روح گنگ و کر من تو را حکم می‌کنم از او در آی ودیگر داخل او مشو!»"},{"v":26,"t":"پس صیحه زده و او رابشدت مصروع نموده، بیرون آمد و مانند مرده گشت، چنانکه بسیاری گفتند که فوت شد."},{"v":27,"t":"اما عیسی دستش را گرفته، برخیزانیدش که برپاایستاد."},{"v":28,"t":"و چون به خانه در‌آمد، شاگردانش درخلوت از او پرسیدند: «چرا ما نتوانستیم او رابیرون کنیم؟»"},{"v":29,"t":"ایشان را گفت: «این جنس به هیچ وجه بیرون نمی رود جز به دعا.»"},{"v":30,"t":"و از آنجا روانه شده، در جلیل می‌گشتند ونمی خواست کسی او را بشناسد،"},{"v":31,"t":"زیرا که شاگردان خود را اعلام فرموده، می‌گفت: «پسرانسان به‌دست مردم تسلیم می‌شود و او راخواهند کشت و بعد از مقتول شدن، روز سوم خواهد برخاست.»"},{"v":32,"t":"اما این سخن را درک نکردند و ترسیدند که از او بپرسند."},{"v":33,"t":"و وارد کفرناحوم شده، چون به خانه درآمد، از ایشان پرسید که «در بین راه با یک دیگرچه مباحثه می‌کردید؟»"},{"v":34,"t":"اما ایشان خاموش ماندند، از آنجا که در راه با یکدیگر گفتگومی کردند در اینکه کیست بزرگتر."},{"v":35,"t":"پس نشسته، آن دوازده را طلبیده، بدیشان گفت: «هر‌که می‌خواهد مقدم باشد موخر و غلام همه بود."},{"v":36,"t":"پس طفلی را برداشته، در میان ایشان بر پا نمودو او را در آغوش کشیده، به ایشان گفت:"},{"v":37,"t":"«هرکه یکی از این کودکان را به اسم من قبول کند، مراقبول کرده است و هر‌که مرا پذیرفت نه مرا بلکه فرستنده مرا پذیرفته باشد."},{"v":38,"t":"آنگاه یوحنا ملتفت شده، بدو گفت: «ای استاد، شخصی را دیدیم که به نام تو دیوها بیرون می‌کرد و متابعت ما نمی نمود؛ و چون متابعت مانمی کرد، او را ممانعت نمودیم.»"},{"v":39,"t":"عیسی گفت: «او را منع مکنید، زیرا هیچ‌کس نیست که معجزه‌ای به نام من بنماید و بتواند به زودی درحق من بد گوید."},{"v":40,"t":"زیرا هر‌که ضد ما نیست باماست."},{"v":41,"t":"و هر‌که شما را از این‌رو که از آن مسیح هستید، کاسه‌ای آب به اسم من بنوشاند، هرآینه به شما می‌گویم اجر خود را ضایع نخواهد کرد."},{"v":42,"t":"و هر‌که یکی از این کودکان را که به من ایمان آورند، لغزش دهد، او را بهتر است که سنگ آسیایی بر گردنش آویخته، در دریا افکنده شود."},{"v":43,"t":"پس هرگاه دستت تو را بلغزاند، آن را ببرزیرا تو را بهتر است که شل داخل حیات شوی، ازاینکه با دو دست وارد جهنم گردی، در آتشی که خاموشی نپذیرد؛"},{"v":44,"t":"جایی که کرم ایشان نمیرد وآتش، خاموشی نپذیرد."},{"v":45,"t":"و هرگاه پایت تو رابلغزاند، قطعش کن زیرا تو را مفیدتر است که لنگ داخل حیات شوی از آنکه با دو پا به جهنم افکنده شوی، در آتشی که خاموشی نپذیرد؛"},{"v":46,"t":"آنجایی که کرم ایشان نمیرد و آتش، خاموش نشود."},{"v":47,"t":"و هر گاه چشم تو تو را لغزش دهد، قلعش کن زیرا تو را بهتر است که با یک چشم داخل ملکوت خدا شوی، از آنکه با دو چشم درآتش جهنم انداخته شوی،"},{"v":48,"t":"جایی که کرم ایشان نمیرد و آتش خاموشی نیابد."},{"v":49,"t":"زیرا هرکس به آتش، نمکین خواهد شد و هر قربانی به نمک، نمکین می‌گردد."},{"v":50,"t":"نمک نیکو است، لیکن هر گاه نمک فاسد گردد به چه چیز آن را اصلاح می‌کنید؟ پس در خود نمک بدارید و با یکدیگرصلح نمایید.»"}]},"10":{"fa":[{"v":1,"t":"و از آنجا برخاسته، از آن طرف اردن به نواحی یهودیه آمد. و گروهی باز نزدوی جمع شدند و او برحسب عادت خود، بازبدیشان تعلیم می‌داد."},{"v":2,"t":"آنگاه فریسیان پیش آمده، از روی امتحان ازاو سوال نمودند که «آیا مرد را طلاق دادن زن خویش جایز است.»"},{"v":3,"t":"در جواب ایشان گفت: «موسی شما را چه فرموده است؟»"},{"v":4,"t":"گفتند: «موسی اجازت داد که طلاق نامه بنویسند و رهاکنند.»"},{"v":5,"t":"عیسی در جواب ایشان گفت: «به‌سبب سنگدلی شما این حکم را برای شما نوشت."},{"v":6,"t":"لیکن از ابتدای خلقت، خدا ایشان را مرد و زن آفرید."},{"v":7,"t":"از آن جهت باید مرد پدر و مادر خود را ترک کرده، با زن خویش بپیوندد،"},{"v":8,"t":"و این دو یک تن خواهند بود چنانکه از آن پس دو نیستند بلکه یک جسد."},{"v":9,"t":"پس آنچه خدا پیوست، انسان آن راجدا نکند.»"},{"v":10,"t":"و در خانه باز شاگردانش از این مقدمه ازوی سوال نمودند."},{"v":11,"t":"بدیشان گفت: «هر‌که زن خود را طلاق دهد و دیگری را نکاح کند، بر‌حق وی زنا کرده باشد."},{"v":12,"t":"و اگر زن از شوهر خود جداشود و منکوحه دیگری گردد، مرتکب زنا شود.»"},{"v":13,"t":"و بچه های کوچک را نزد او آوردند تاایشان را لمس نماید؛ اما شاگردان آورندگان رامنع کردند."},{"v":14,"t":"چون عیسی این را بدید، خشم نموده، بدیشان گفت: «بگذارید که بچه های کوچک نزد من آیند و ایشان را مانع نشوید، زیراملکوت خدا از امثال اینها است."},{"v":15,"t":"هرآینه به شما می‌گویم هر‌که ملکوت خدا را مثل بچه کوچک قبول نکند، داخل آن نشود.»"},{"v":16,"t":"پس ایشان را در آغوش کشید و دست بر ایشان نهاده، برکت داد."},{"v":17,"t":"چون به راه می‌رفت، شخصی دوان دوان آمده، پیش او زانو زده، سوال نمود که «ای استادنیکو چه کنم تا وارث حیات جاودانی شوم؟"},{"v":18,"t":"عیسی بدو گفت: «چرا مرا نیکو گفتی و حال آنکه کسی نیکو نیست جز خدا فقط؟"},{"v":19,"t":"احکام را می دانی، زنا مکن، قتل مکن، دزدی مکن، شهادت دروغ مده، دغابازی مکن، پدر و مادر خود راحرمت دار.»"},{"v":20,"t":"او در جواب وی گفت: «ای استاد، این همه را از طفولیت نگاه داشتم.»"},{"v":21,"t":"عیسی به وی نگریسته، او را محبت نمود وگفت: «تو را یک چیز ناقص است: برو و آنچه داری بفروش و به فقرا بده که در آسمان گنجی خواهی یافت و بیا صلیب را برداشته، مرا پیروی کن.»"},{"v":22,"t":"لیکن او از این سخن ترش رو و محزون گشته، روانه گردید زیرا اموال بسیار داشت."},{"v":23,"t":"آنگاه عیسی گرداگرد خود نگریسته، به شاگردان خود گفت: «چه دشوار است که توانگران داخل ملکوت خدا شوند.»"},{"v":24,"t":"چون شاگردانش از سخنان او در حیرت افتادند، عیسی باز توجه نموده، بدیشان گفت: «ای فرزندان، چه دشوار است دخول آنانی که به مال و اموال توکل دارند در ملکوت خدا!"},{"v":25,"t":"سهل تر است که شتر به سوراخ سوزن درآید از اینکه شخص دولتمند به ملکوت خدا داخل شود!»"},{"v":26,"t":"ایشان بغایت متحیرگشته، با یکدیگر می‌گفتند: «پس که می‌تواندنجات یابد؟»"},{"v":27,"t":"عیسی به ایشان نظر کرده، گفت: «نزد انسان محال است لیکن نزد خدا نیست زیراکه همه‌چیز نزد خدا ممکن است.»"},{"v":28,"t":"پطرس بدوگفتن گرفت که «اینک ما همه‌چیز را ترک کرده، تورا پیروی کرده‌ایم.»"},{"v":29,"t":"عیسی جواب فرمود: «هرآینه به شما می‌گویم کسی نیست که خانه یابرادران یا خواهران یا پدر یا مادر یا زن یا اولاد یااملاک را بجهت من و انجیل ترک کند،"},{"v":30,"t":"جزاینکه الحال در این زمان صد چندان یابد ازخانه‌ها و برادران و خواهران و مادران و فرزندان و املاک با زحمات، و در عالم آینده حیات جاودانی را."},{"v":31,"t":"اما بسا اولین که آخرین می‌گردندو آخرین اولین.»"},{"v":32,"t":"و چون در راه به سوی اورشلیم می‌رفتند وعیسی در جلو ایشان می‌خرامید، در حیرت افتادند و چون از عقب او می‌رفتند، ترس بر ایشان مستولی شد. آنگاه آن دوازده را باز به کنارکشیده، شروع کرد به اطلاع دادن به ایشان از آنچه بر وی وارد می‌شد،"},{"v":33,"t":"که «اینک به اورشلیم می‌رویم و پسر انسان به‌دست روسای کهنه وکاتبان تسلیم شود و بر وی فتوای قتل دهند و اورا به امتها سپارند،"},{"v":34,"t":"و بر وی سخریه نموده، تازیانه‌اش زنند و آب دهان بر وی افکنده، او راخواهند کشت و روز سوم خواهد برخاست.»"},{"v":35,"t":"آنگاه یعقوب و یوحنا دو پسر زبدی نزدوی آمده، گفتند: «ای استاد، می‌خواهیم آنچه ازتو سوال کنیم برای ما بکنی.»"},{"v":36,"t":"ایشان را گفت: «چه می‌خواهید برای شما بکنم؟»"},{"v":37,"t":"گفتند: «به ما عطا فرما که یکی به طرف راست و دیگری برچپ تو در جلال تو بنشینیم.»"},{"v":38,"t":"عیسی ایشان راگفت: «نمی فهمید آنچه می‌خواهید. آیا می‌توانیدآن پیاله‌ای را که من می‌نوشم، بنوشید و تعمیدی را که من می‌پذیرم، بپذیرید؟»"},{"v":39,"t":"وی را گفتند: «می‌توانیم.» عیسی بدیشان گفت: «پیاله‌ای را که من می‌نوشم خواهید آشامید و تعمیدی را که من می‌پذیرم خواهید پذیرفت."},{"v":40,"t":"لیکن نشستن به‌دست راست و چپ من از آن من نیست که بدهم جز آنانی را که از بهر ایشان مهیا شده است.»"},{"v":41,"t":"وآن ده نفر چون شنیدند بر یعقوب و یوحنا خشم گرفتند."},{"v":42,"t":"عیسی ایشان را خوانده، به ایشان گفت: «می‌دانید آنانی که حکام امتها شمرده می‌شوند برایشان ریاست می‌کنند و بزرگانشان بر ایشان مسلطند."},{"v":43,"t":"لیکن در میان شما چنین نخواهد بود، بلکه هر‌که خواهد در میان شما بزرگ شود، خادم شما باشد."},{"v":44,"t":"و هر‌که خواهد مقدم بر شما شود، غلام همه باشد."},{"v":45,"t":"زیرا که پسر انسان نیز نیامده تامخدوم شود بلکه تا خدمت کند و تا جان خود رافدای بسیاری کند.»"},{"v":46,"t":"و وارد اریحا شدند. و وقتی که او باشاگردان خود و جمعی کثیر از اریحا بیرون می‌رفت، بارتیمائوس کور، پسر تیماوس بر کناره راه نشسته، گدایی می‌کرد."},{"v":47,"t":"چون شنید که عیسی ناصری است، فریاد کردن گرفت و گفت: «ای عیسی ابن داود بر من ترحم کن.»"},{"v":48,"t":"و چندان‌که بسیاری او را نهیب می‌دادند که خاموش شود، زیادتر فریاد برمی آورد که پسر داودا بر من ترحم فرما."},{"v":49,"t":"پس عیسی ایستاده، فرمود تا او را بخوانند. آنگاه آن کور را خوانده، بدو گفتند: «خاطر جمع دار برخیز که تو را می‌خواند.»"},{"v":50,"t":"درساعت ردای خود را دور انداخته، بر پا جست ونزد عیسی آمد."},{"v":51,"t":"عیسی به وی التفات نموده، گفت: «چه می‌خواهی از بهر تو نمایم؟» کور بدوگفت: «یا سیدی آنکه بینایی یابم.»"},{"v":52,"t":"عیسی بدوگفت: «برو که ایمانت تو را شفا داده است.» درساعت بینا گشته، از عقب عیسی در راه روانه شد."}]},"11":{"fa":[{"v":1,"t":"و چون نزدیک به اورشلیم به بیت‌فاجی و بیت عنیا بر کوه زیتون رسیدند، دو نفراز شاگردان خود را فرستاده،"},{"v":2,"t":"بدیشان گفت: «بدین قریه‌ای که پیش روی شما است بروید وچون وارد آن شدید، درساعت کره الاغی را بسته خواهید یافت که تا به حال هیچ‌کس بر آن سوارنشده؛ آن را باز کرده، بیاورید."},{"v":3,"t":"و هرگاه کسی به شما گوید چرا چنین می‌کنید، گویید خداوندبدین احتیاج دارد؛ بی‌تامل آن را به اینجا خواهدفرستاد.»"},{"v":4,"t":"پس رفته کره‌ای بیرون دروازه درشارع عام بسته یافتند و آن را باز می‌کردند،"},{"v":5,"t":"که بعضی از حاضرین بدیشان گفتند: «چه‌کار داریدکه کره را باز می‌کنید؟»"},{"v":6,"t":"آن دو نفر چنانکه عیسی فرموده بود، بدیشان گفتند. پس ایشان را اجازت دادند."},{"v":7,"t":"آنگاه کره را به نزد عیسی آورده، رخت خود را بر آن افکندند تا بر آن سوار شد."},{"v":8,"t":"وبسیاری رختهای خود و بعضی شاخه‌ها ازدرختان بریده، بر راه گسترانیدند."},{"v":9,"t":"و آنانی که پیش و پس می‌رفتند، فریادکنان می‌گفتند: «هوشیعانا، مبارک باد کسی‌که به نام خداوندمی آید."},{"v":10,"t":"مبارک باد ملکوت پدر ما داود که می‌آید به اسم خداوند. هوشیعانا در اعلی علیین.»"},{"v":11,"t":"و عیسی وارد اورشلیم شده، به هیکل درآمد وبه همه‌چیز ملاحظه نمود. چون وقت شام شد باآن دوازده به بیت عنیا رفت."},{"v":12,"t":"بامدادان چون از بیت عنیا بیرون می‌آمدند، گرسنه شد."},{"v":13,"t":"ناگاه درخت انجیری که برگ داشت از دور دیده، آمد تا شاید چیزی بر آن بیابد. اما چون نزد آن رسید، جز برگ بر آن هیچ نیافت زیرا که موسم انجیر نرسیده بود."},{"v":14,"t":"پس عیسی توجه نموده، بدان فرمود: «از این پس تا به ابد، هیچ‌کس از تو میوه نخواهد خورد.» وشاگردانش شنیدند."},{"v":15,"t":"پس وارد اورشلیم شدند. و چون عیسی داخل هیکل گشت، به بیرون کردن آنانی که درهیکل خرید و فروش می‌کردند شروع نمود وتخت های صرافان و کرسیهای کبوترفروشان راواژگون ساخت،"},{"v":16,"t":"و نگذاشت که کسی با ظرفی از میان هیکل بگذرد،"},{"v":17,"t":"و تعلیم داده، گفت: «آیامکتوب نیست که خانه من خانه عبادت تمامی امتها نامیده خواهد شد؟ اما شما آن را مغاره دزدان ساخته‌اید.»"},{"v":18,"t":"چون روسای کهنه و کاتبان این را بشنیدند، در صدد آن شدند که او را چطور هلاک سازندزیرا که از وی ترسیدند چون که همه مردم ازتعلیم وی متحیر می‌بودند."},{"v":19,"t":"چون شام شد، از شهر بیرون رفت."},{"v":20,"t":"صبحگاهان، در اثنای راه، درخت انجیر رااز ریشه خشک یافتند."},{"v":21,"t":"پطرس به‌خاطر آورده، وی را گفت: «ای استاد، اینک درخت انجیری که نفرینش کردی خشک شده!»"},{"v":22,"t":"عیسی در جواب ایشان گفت: «به خدا ایمان آورید،"},{"v":23,"t":"زیرا که هرآینه به شما می‌گویم هر‌که بدین کوه گویدمنتقل شده، به دریا افکنده شو و در دل خود شک نداشته باشد بلکه یقین دارد که آنچه گویدمی شود، هرآینه هر‌آنچه گوید بدو عطا شود."},{"v":24,"t":"بنابراین به شما می‌گویم آنچه در عبادت سوال می‌کنید، یقین بدانید که آن را یافته‌اید و به شماعطا خواهد شد."},{"v":25,"t":"و وقتی که به دعا بایستید، هرگاه کسی به شما خطا کرده باشد، او را ببخشید تاآنکه پدر شما نیز که در آسمان است، خطایای شما را معاف دارد."},{"v":26,"t":"اما هرگاه شما نبخشید، پدر شما نیز که درآسمان است تقصیرهای شما را نخواهد بخشید.»"},{"v":27,"t":"و باز به اورشلیم آمدند. و هنگامی که او درهیکل می‌خرامید، روسای کهنه و کاتبان و مشایخ نزد وی آمده،"},{"v":28,"t":"گفتندش: «به چه قدرت این کارها را می‌کنی و کیست که این قدرت را به توداده است تا این اعمال را به‌جا آری؟»"},{"v":29,"t":"عیسی در جواب ایشان گفت: «من از شما نیز سخنی می پرسم، مرا جواب دهید تا من هم به شما گویم به چه قدرت این کارها را می‌کنم."},{"v":30,"t":"تعمید یحیی ازآسمان بود یا از انسان؟ مرا جواب دهید.»"},{"v":31,"t":"ایشان در دلهای خود تفکر نموده، گفتند: «اگرگوییم از آسمان بود، هرآینه گوید پس چرا بدوایمان نیاوردید."},{"v":32,"t":"و اگر گوییم از انسان بود، » ازخلق بیم داشتند از آنجا که همه یحیی را نبی‌ای برحق می‌دانستند."},{"v":33,"t":"پس در جواب عیسی گفتند: «نمی دانیم.» عیسی بدیشان جواب داد: «من هم شما را نمی گویم که به کدام قدرت این کارها را به‌جا می‌آورم.»"}]},"12":{"fa":[{"v":1,"t":"پس به مثل‌ها به ایشان آغاز سخن نمودکه «شخصی تاکستانی غرس نموده، حصاری گردش کشید و چرخشتی بساخت وبرجی بنا کرده، آن را به دهقانان سپرد و سفر کرد."},{"v":2,"t":"و در موسم، نوکری نزد دهقانان فرستاد تا ازمیوه باغ از باغبانان بگیرد."},{"v":3,"t":"اما ایشان او را گرفته، زدند و تهی‌دست روانه نمودند."},{"v":4,"t":"باز نوکری دیگرنزد ایشان روانه نمود. او را نیز سنگسار کرده، سراو را شکستند و بی‌حرمت کرده، برگردانیدندش."},{"v":5,"t":"پس یک نفر دیگر فرستاده، او را نیز کشتند و بسادیگران را که بعضی را زدند و بعضی را به قتل رسانیدند."},{"v":6,"t":"و بالاخره یک پسر حبیب خود راباقی داشت. او را نزد ایشان فرستاده، گفت: پسرمرا حرمت خواهند داشت."},{"v":7,"t":"لیکن دهقانان با خودگفتند: این وارث است؛ بیایید او را بکشیم تامیراث از آن ما گردد."},{"v":8,"t":"پس او را گرفته، مقتول ساختند و او را بیرون از تاکستان افکندند."},{"v":9,"t":"پس صاحب تاکستان چه خواهد کرد؟ او خواهدآمد و آن باغبان را هلاک ساخته، باغ را به دیگران خواهد سپرد."},{"v":10,"t":"آیا این نوشته رانخوانده‌اید: سنگی که معمارانش رد کردند، همان سر زاویه گردید؟"},{"v":11,"t":"این از جانب خداوند شد و در نظر ما عجیب است."},{"v":12,"t":"آنگاه خواستند او را گرفتار سازند، اما از خلق می‌ترسیدند، زیرا می‌دانستند که این مثل رابرای ایشان آورد. پس او را واگذارده، برفتند."},{"v":13,"t":"و چند نفر از فریسیان و هیرودیان را نزدوی فرستادند تا او را به سخنی به دام آورند."},{"v":14,"t":"ایشان آمده، بدو گفتند: «ای استاد، ما را یقین است که تو راستگو هستی و از کسی باک نداری، چون که به ظاهر مردم نمی نگری بلکه طریق خدارا به راستی تعلیم می‌نمایی. جزیه دادن به قیصرجایز است یا نه؟ بدهیم یا ندهیم؟"},{"v":15,"t":"اما اوریاکاری ایشان را درک کرده، بدیشان گفت: «چرامرا امتحان می‌کنید؟ دیناری نزد من آرید تا آن راببینم.»"},{"v":16,"t":"چون آن را حاضر کردند، بدیشان گفت: «این صورت و رقم از آن کیست؟» وی راگفتند: «از آن قیصر.»"},{"v":17,"t":"عیسی در جواب ایشان گفت: «آنچه از قیصر است، به قیصر رد کنید وآنچه از خداست، به خدا.» و از او متعجب شدند."},{"v":18,"t":"و صدوقیان که منکر هستند نزد وی آمده، از او سوال نموده، گفتند:"},{"v":19,"t":"«ای استاد، موسی به ما نوشت که هرگاه برادر کسی بمیرد و زنی بازگذاشته، اولادی نداشته باشد، برادرش زن او رابگیرد تا از بهر برادر خود نسلی پیدا نماید."},{"v":20,"t":"پس هفت برادر بودند که نخستین، زنی گرفته، بمرد واولادی نگذاشت."},{"v":21,"t":"پس ثانی او را گرفته، هم بی‌اولاد فوت شد و همچنین سومی."},{"v":22,"t":"تا آنکه آن هفت او را گرفتند و اولادی نگذاشتند و بعد ازهمه، زن فوت شد."},{"v":23,"t":"پس در قیامت چون برخیزند، زن کدام‌یک از ایشان خواهد بود ازآنجهت که هر هفت، او را به زنی گرفته بودند؟»"},{"v":24,"t":"عیسی در جواب ایشان گفت: «آیا گمراه نیستید از آنرو که کتب و قوت خدا را نمی دانید؟"},{"v":25,"t":"زیرا هنگامی که از مردگان برخیزند، نه نکاح می‌کنند و نه منکوحه می‌گردند، بلکه مانندفرشتگان، در آسمان می‌باشند."},{"v":26,"t":"اما در باب مردگان که برمی خیزند، در کتاب موسی در ذکربوته نخوانده‌اید چگونه خدا او را خطاب کرده، گفت که منم خدای ابراهیم و خدای اسحاق وخدای یعقوب."},{"v":27,"t":"و او خدای مردگان نیست بلکه خدای زندگان است. پس شما بسیار گمراه شده‌اید.»"},{"v":28,"t":"و یکی از کاتبان، چون مباحثه ایشان را شنیده، دید که ایشان را جواب نیکو داد، پیش آمده، از او پرسید که «اول همه احکام کدام است؟»"},{"v":29,"t":"عیسی او را جواب داد که «اول همه احکام این است که بشنو‌ای اسرائیل، خداوندخدای ما خداوند واحد است."},{"v":30,"t":"و خداوندخدای خود را به تمامی دل و تمامی جان وتمامی خاطر و تمامی قوت خود محبت نما، که اول از احکام این است."},{"v":31,"t":"و دوم مثل اول است که همسایه خود را چون نفس خود محبت نما. بزرگتر از این دو، حکمی نیست.»"},{"v":32,"t":"کاتب وی راگفت: «آفرین‌ای استاد، نیکو گفتی، زیرا خداواحد است و سوای او دیگری نیست،"},{"v":33,"t":"و او رابه تمامی دل و تمامی فهم و تمامی نفس و تمامی قوت محبت نمودن و همسایه خود را مثل خودمحبت نمودن، از همه قربانی های سوختنی وهدایا افضل است.»"},{"v":34,"t":"چون عیسی بدید که عاقلانه جواب داد، به وی گفت: «از ملکوت خدادور نیستی.» و بعد از آن، هیچ‌کس جرات نکردکه از او سوالی کند."},{"v":35,"t":"و هنگامی که عیسی در هیکل تعلیم می‌داد، متوجه شده، گفت: «چگونه کاتبان می‌گویند که مسیح پسر داود است؟"},{"v":36,"t":"و حال آنکه خود داود در روح‌القدس می‌گوید که خداوند به خداوند من گفت برطرف راست من بنشین تا دشمنان تو را پای انداز تو سازم؟"},{"v":37,"t":"خودداود او را خداوند می‌خواند؛ پس چگونه او راپسر می‌باشد؟» و عوام الناس کلام او را به خشنودی می‌شنیدند."},{"v":38,"t":"پس در تعلیم خود گفت: «از کاتبان احتیاطکنید که خرامیدن در لباس دراز و تعظیم های دربازارها"},{"v":39,"t":"و کرسی های اول در کنایس و جایهای صدر در ضیافت‌ها را دوست می‌دارند."},{"v":40,"t":"اینان که خانه های بیوه‌زنان را می‌بلعند و نماز را به ریاطول می‌دهند، عقوبت شدیدتر خواهند یافت.»"},{"v":41,"t":"و عیسی در مقابل بیت‌المال نشسته، نظاره می‌کرد که مردم به چه وضع پول به بیت‌المال می‌اندازند؛ و بسیاری از دولتمندان، بسیارمی انداختند."},{"v":42,"t":"آنگاه بیوه‌زنی فقیر آمده، دوفلس که یک ربع باشد انداخت."},{"v":43,"t":"پس شاگردان خود را پیش خوانده، به ایشان گفت: «هرآینه به شما می‌گویم این بیوه‌زن مسکین از همه آنانی که در خزانه انداختند، بیشتر داد."},{"v":44,"t":"زیرا که همه ایشان از زیادتی خود دادند، لیکن این زن ازحاجتمندی خود، آنچه داشت انداخت، یعنی تمام معیشت خود را.»"}]},"13":{"fa":[{"v":1,"t":"و چون او از هیکل بیرون می‌رفت، یکی از شاگردانش بدو گفت: «ای استادملاحظه فرما چه نوع سنگها و چه عمارت ها است!»"},{"v":2,"t":"عیسی در جواب وی گفت: «آیا این عمارت های عظیمه را می‌نگری؟ بدان که سنگی بر سنگی گذارده نخواهد شد، مگر آنکه به زیرافکنده شود!»"},{"v":3,"t":"و چون او بر کوه زیتون، مقابل هیکل نشسته بود، پطرس و یعقوب و یوحنا و اندریاس سر ازوی پرسیدند:"},{"v":4,"t":"«ما را خبر بده که این امور کی واقع می‌شود و علامت نزدیک شدن این امورچیست؟»"},{"v":5,"t":"آنگاه عیسی در جواب ایشان سخن آغازکرد که «زنهار کسی شما را گمراه نکند!"},{"v":6,"t":"زیرا که بسیاری به نام من آمده، خواهند گفت که من هستم و بسیاری را گمراه خواهند نمود."},{"v":7,"t":"اما چون جنگها و اخبار جنگها را بشنوید، مضطرب مشوید زیرا که وقوع این حوادث ضروری است لیکن انتها هنوز نیست."},{"v":8,"t":"زیرا که امتی بر امتی ومملکتی بر مملکتی خواهند برخاست و زلزله هادر جایها حادث خواهد شد و قحطی‌ها واغتشاش‌ها پدید می‌آید؛ و اینها ابتدای دردهای زه می‌باشد."},{"v":9,"t":"«لیکن شما از برای خود احتیاط کنید زیرا که شما را به شوراها خواهند سپرد و در کنایس تازیانه‌ها خواهند زد و شما را پیش حکام وپادشاهان بخاطر من حاضر خواهند کرد تا برایشان شهادتی شود."},{"v":10,"t":"و لازم است که انجیل اول بر تمامی امتها موعظه شود."},{"v":11,"t":"و چون شما راگرفته، تسلیم کنند، میندیشید که چه بگویید ومتفکر مباشید بلکه آنچه در آن ساعت به شما عطاشود، آن را گویید زیرا گوینده شما نیستید بلکه روح‌القدس است."},{"v":12,"t":"آنگاه برادر، برادر را و پدر، فرزند را به هلاکت خواهند سپرد و فرزندان بروالدین خود برخاسته، ایشان را به قتل خواهندرسانید."},{"v":13,"t":"و تمام خلق بجهت اسم من شما رادشمن خواهند داشت. اما هر‌که تا به آخر صبرکند، همان نجات یابد."},{"v":14,"t":"«پس چون مکروه ویرانی را که به زبان دانیال نبی گفته شده است، در جایی که نمی بایدبرپا بینید - آنکه می‌خواند بفهمد - آنگاه آنانی که در یهودیه می‌باشند، به کوهستان فرار کنند،"},{"v":15,"t":"و هر‌که بر بام باشد، به زیر نیاید و به خانه داخل نشود تا چیزی از آن ببرد،"},{"v":16,"t":"و آنکه در مزرعه است، برنگردد تا رخت خود را بردارد."},{"v":17,"t":"اما وای بر آبستنان و شیر دهندگان در آن ایام."},{"v":18,"t":"و دعاکنید که فرار شما در زمستان نشود،"},{"v":19,"t":"زیرا که درآن ایام، چنان مصیبتی خواهد شد که از ابتدای خلقتی که خدا آفرید تاکنون نشده و نخواهد شد."},{"v":20,"t":"و اگر خداوند آن روزها را کوتاه نکردی، هیچ بشری نجات نیافتی. لیکن بجهت برگزیدگانی که انتخاب نموده است، آن ایام را کوتاه ساخت."},{"v":21,"t":"«پس هرگاه کسی به شما گوید اینک مسیح در اینجاست یا اینک در آنجا، باور مکنید."},{"v":22,"t":"زانرو که مسیحان دروغ و انبیای کذبه ظاهرشده، آیات و معجزات از ایشان صادر خواهدشد، بقسمی که اگر ممکن بودی، برگزیدگان را هم گمراه نمودندی."},{"v":23,"t":"لیکن شما برحذر باشید!"},{"v":24,"t":"و درآن روزهای بعد از آن مصیبت خورشید تاریک گردد و ماه نور خود را بازگیرد،"},{"v":25,"t":"و ستارگان ازآسمان فرو ریزند و قوای افلاک متزلزل خواهدگشت."},{"v":26,"t":"آنگاه پسر انسان را بینند که با قوت وجلال عظیم بر ابرها می‌آید."},{"v":27,"t":"در آن وقت، فرشتگان خود را از جهات اربعه از انتهای زمین تابه اقصای فلک فراهم خواهد آورد."},{"v":28,"t":"«الحال از درخت انجیر مثلش را فراگیریدکه چون شاخه‌اش نازک شده، برگ می‌آوردمی دانید که تابستان نزدیک است."},{"v":29,"t":"همچنین شما نیز چون این چیزها را واقع بینید، بدانید که نزدیک بلکه بر در است."},{"v":30,"t":"هرآینه به شمامی گویم تا جمیع این حوادث واقع نشود، این فرقه نخواهند گذشت."},{"v":31,"t":"آسمان و زمین زایل می‌شود، لیکن کلمات من هرگز زایل نشود."},{"v":32,"t":"ولی از آن روز و ساعت غیر از پدرهیچ‌کس اطلاع ندارد، نه فرشتگان در آسمان و نه پسر هم."},{"v":33,"t":"«پس برحذر و بیدار شده، دعا کنیدزیرا نمی دانید که آن وقت کی می‌شود."},{"v":34,"t":"مثل کسی‌که عازم سفر شده، خانه خود را واگذارد وخادمان خود را قدرت داده، هر یکی را به شغلی خاص مقرر نماید و دربان را امر فرماید که بیداربماند."},{"v":35,"t":"پس بیدار باشید زیرا نمی دانید که در چه وقت صاحب‌خانه می‌آید، در شام یا نصف شب یا بانگ خروس یا صبح."},{"v":36,"t":"مبادا ناگهان آمده شما را خفته یابد."},{"v":37,"t":"اما آنچه به شما می‌گویم، به همه می‌گویم: بیدار باشید!»"}]},"14":{"fa":[{"v":1,"t":"و بعد از دو روز، عید فصح و فطیر بودکه روسای کهنه و کاتبان مترصد بودندکه به چه حیله او را دستگیر کرده، به قتل رسانند."},{"v":2,"t":"لیکن می‌گفتند: «نه در عید مبادا در قوم اغتشاشی پدید آید.»"},{"v":3,"t":"و هنگامی که او در بیت عنیا در خانه شمعون ابرص به غذا نشسته بود، زنی با شیشه‌ای از عطرگرانبها از سنبل خالص آمده، شیشه را شکسته، برسر وی ریخت."},{"v":4,"t":"و بعضی در خود خشم نموده، گفتند: «چرا این عطر تلف شد؟"},{"v":5,"t":"زیرا ممکن بوداین عطر زیادتر از سیصد دینار فروخته، به فقراداده شود.» و آن زن را سرزنش نمودند."},{"v":6,"t":"اماعیسی گفت: «او را واگذارید! از برای چه او رازحمت می‌دهید؟ زیرا که با من کاری نیکو کرده است،"},{"v":7,"t":"زیرا که فقرا را همیشه با خود دارید وهرگاه بخواهید می‌توانید با ایشان احسان کنید، لیکن مرا با خود دائم ندارید."},{"v":8,"t":"آنچه در قوه اوبود کرد، زیرا که جسد مرا بجهت دفن، پیش تدهین کرد."},{"v":9,"t":"هرآینه به شما می‌گویم در هر جایی از تمام عالم که به این انجیل موعظه شود، آنچه این زن کرد نیز بجهت یادگاری وی مذکور خواهد شد.»"},{"v":10,"t":"پس یهودای اسخریوطی که یکی از آن دوازده بود، به نزد روسای کهنه رفت تا او رابدیشان تسلیم کند."},{"v":11,"t":"ایشان سخن او را شنیده، شاد شدند و بدو وعده دادند که نقدی بدو بدهند. و او در صدد فرصت موافق برای گرفتاری وی برآمد."},{"v":12,"t":"و روز اول از عید فطیر که در آن فصح راذبح می‌کردند، شاگردانش به وی گفتند: «کجامی خواهی برویم تدارک بینیم تا فصح رابخوری؟»"},{"v":13,"t":"پس دو نفر از شاگردان خود رافرستاده، بدیشان گفت: «به شهر بروید و شخصی با سبوی آب به شما خواهد برخورد. از عقب وی بروید،"},{"v":14,"t":"و به هرجایی که درآید صاحب‌خانه راگویید: استاد می‌گوید مهمانخانه کجا است تافصح را با شاگردان خود آنجا صرف کنم؟"},{"v":15,"t":"و اوبالاخانه بزرگ مفروش و آماده به شما نشان می‌دهد. آنجا از بهر ما تدارک بینید.»"},{"v":16,"t":"شاگردانش روانه شدند و به شهر رفته، چنانکه او فرموده بود، یافتند و فصح را آماده ساختند."},{"v":17,"t":"شامگاهان با آن دوازده آمد."},{"v":18,"t":"و چون نشسته غذا می‌خوردند، عیسی گفت: «هرآینه به شما می‌گویم که، یکی از شما که با من غذامی خورد، مرا تسلیم خواهد کرد.»"},{"v":19,"t":"ایشان غمگین گشته، یک یک گفتن گرفتند که آیا من آنم و دیگری که آیا من هستم."},{"v":20,"t":"او در جواب ایشان گفت: «یکی از دوازده که با من دست در قاب فروبرد!"},{"v":21,"t":"به درستی که پسر انسان بطوری که درباره او مکتوب است، رحلت می‌کند. لیکن وای بر آن کسی‌که پسر انسان به واسطه او تسلیم شود. او رابهتر می‌بود که تولد نیافتی.»"},{"v":22,"t":"و چون غذا می‌خوردند، عیسی نان راگرفته، برکت داد و پاره کرده، بدیشان داد و گفت: «بگیرید و بخورید که این جسد من است.»"},{"v":23,"t":"وپیاله‌ای گرفته، شکر نمود و به ایشان داد و همه ازآن آشامیدند"},{"v":24,"t":"و بدیشان گفت: «این است خون من از عهد جدید که در راه بسیاری ریخته می‌شود."},{"v":25,"t":"هرآینه به شما می‌گویم بعد از این ازعصیر انگور نخورم تا آن روزی که در ملکوت خدا آن را تازه بنوشم."},{"v":26,"t":"و بعد از خواندن تسبیح، به سوی کوه زیتون بیرون رفتند."},{"v":27,"t":"عیسی ایشان را گفت: «همانا همه شما امشب در من لغزش خورید، زیرامکتوب است شبان را می‌زنم و گوسفندان پراکنده خواهند شد."},{"v":28,"t":"اما بعد از برخاستنم، پیش از شمابه جلیل خواهم رفت."},{"v":29,"t":"پطرس به وی گفت: «هرگاه همه لغزش خورند، من هرگز نخورم.»"},{"v":30,"t":"عیسی وی را گفت: «هرآینه به تو می‌گویم که امروز در همین شب، قبل از آنکه خروس دومرتبه بانگ زند، تو سه مرتبه مرا انکار خواهی نمود.»"},{"v":31,"t":"لیکن او به تاکید زیادتر می‌گفت: «هرگاه مردنم با تو لازم افتد، تو را هرگز انکار نکنم.» ودیگران نیز همچنان گفتند."},{"v":32,"t":"و چون به موضعی که جتسیمانی نام داشت رسیدند، به شاگردان خود گفت: «در اینجابنشینید تا دعا کنم.»"},{"v":33,"t":"و پطرس و یعقوب ویوحنا را همراه برداشته، مضطرب و دلتنگ گردید"},{"v":34,"t":"و بدیشان گفت: «نفس من از حزن، مشرف بر موت شد. اینجا بمانید و بیدار باشید.»"},{"v":35,"t":"و قدری پیشتر رفته، به روی بر زمین افتاد ودعا کرد تا اگر ممکن باشد آن ساعت از او بگذرد."},{"v":36,"t":"پس گفت: «یا ابا پدر، همه‌چیز نزد تو ممکن است. این پیاله را از من بگذران، لیکن نه به خواهش من بلکه به اراده تو.»"},{"v":37,"t":"پس چون آمد، ایشان را در خواب دیده، پطرس را گفت: «ای شمعون، در خواب هستی؟ آیا نمی توانستی یک ساعت بیدار باشی؟"},{"v":38,"t":"بیدار باشید و دعا کنید تادر آزمایش نیفتید. روح البته راغب است لیکن جسم ناتوان.»"},{"v":39,"t":"و باز رفته، به همان کلام دعانمود."},{"v":40,"t":"و نیز برگشته، ایشان را در خواب یافت زیرا که چشمان ایشان سنگین شده بود وندانستند او را چه جواب دهند."},{"v":41,"t":"و مرتبه سوم آمده، بدیشان گفت: «مابقی را بخوابید واستراحت کنید. کافی است! ساعت رسیده است. اینک پسر انسان به‌دستهای گناهکاران تسلیم می شود."},{"v":42,"t":"برخیزید برویم که اکنون تسلیم‌کننده من نزدیک شد.»"},{"v":43,"t":"در ساعت وقتی که او هنوز سخن می‌گفت، یهودا که یکی از آن دوازده بود، با گروهی بسیار باشمشیرها و چوبها از جانب روسای کهنه و کاتبان و مشایخ آمدند."},{"v":44,"t":"و تسلیم‌کننده او بدیشان نشانی داده، گفته بود: «هر‌که را ببوسم، همان است. او را بگیرید و با حفظ تمام ببرید.»"},{"v":45,"t":"و درساعت نزد وی شده، گفت: «یا سیدی، یا سیدی.» و وی را بوسید."},{"v":46,"t":"ناگاه دستهای خود را بر وی انداخته، گرفتندش."},{"v":47,"t":"و یکی از حاضرین شمشیر خود را کشیده، بر یکی از غلامان رئیس کهنه زده، گوشش را ببرید."},{"v":48,"t":"عیسی روی بدیشان کرده، گفت: «گویا بر دزد با شمشیرها وچوبها بجهت گرفتن من بیرون آمدید!"},{"v":49,"t":"هر روزدر نزد شما در هیکل تعلیم می‌دادم و مرا نگرفتید. لیکن لازم است که کتب تمام گردد.»"},{"v":50,"t":"آنگاه همه او را واگذارده بگریختند."},{"v":51,"t":"و یک جوانی باچادری بر بدن برهنه خود پیچیده، از عقب اوروانه شد. چون جوانان او را گرفتند،"},{"v":52,"t":"چادر راگذارده، برهنه از دست ایشان گریخت."},{"v":53,"t":"و عیسی را نزد رئیس کهنه بردند و جمیع روسای کاهنان و مشایخ و کاتبان بر او جمع گردیدند."},{"v":54,"t":"و پطرس از دور در عقب او می‌آمد تا به خانه رئیس کهنه درآمده، با ملازمان بنشست ونزدیک آتش خود را گرم می‌نمود."},{"v":55,"t":"و روسای کهنه و جمیع اهل شورا در جستجوی شهادت برعیسی بودند تا او را بکشند و هیچ نیافتند،"},{"v":56,"t":"زیراکه هرچند بسیاری بر وی شهادت دروغ می‌دادند، اما شهادت های ایشان موافق نشد."},{"v":57,"t":"وبعضی برخاسته شهادت دروغ داده، گفتند:"},{"v":58,"t":"«ماشنیدیم که او می‌گفت: من این هیکل ساخته شده به‌دست را خراب می‌کنم و در سه روز، دیگری راناساخته شده به‌دست، بنا می‌کنم.»"},{"v":59,"t":"و در این هم باز شهادت های ایشان موافق نشد."},{"v":60,"t":"پس رئیس کهنه از آن میان برخاسته، ازعیسی پرسیده، گفت: «هیچ جواب نمی دهی؟ چه چیز است که اینها در حق تو شهادت می‌دهند؟»"},{"v":61,"t":"اما او ساکت مانده، هیچ جواب نداد. باز رئیس کهنه از او سوال نموده، گفت: «آیا تو مسیح پسرخدای متبارک هستی؟»"},{"v":62,"t":"عیسی گفت: «من هستم؛ و پسر انسان را خواهید دید که برطرف راست قوت نشسته، در ابرهای آسمان می‌آید.»"},{"v":63,"t":"آنگاه رئیس کهنه جامه خود را چاک زده، گفت: «دیگر‌چه حاجت به شاهدان داریم؟"},{"v":64,"t":"کفر او را شنیدید! چه مصلحت می‌دانید؟» پس همه بر او حکم کردند که مستوجب قتل است."},{"v":65,"t":"و بعضی شروع نمودند به آب دهان بروی انداختن و روی او را پوشانیده، او را می‌زدندو می‌گفتند نبوت کن. ملازمان او را می‌زدند."},{"v":66,"t":"و در وقتی که پطرس در ایوان پایین بود، یکی از کنیزان رئیس کهنه آمد"},{"v":67,"t":"و پطرس راچون دید که خود را گرم می‌کند، بر او نگریسته، گفت: «تو نیز با عیسی ناصری می‌بودی؟"},{"v":68,"t":"اوانکار نموده، گفت: «نمی دانم و نمی فهمم که توچه می‌گویی!» و چون بیرون به دهلیز خانه رفت، ناگاه خروس بانگ زد."},{"v":69,"t":"و بار دیگر آن کنیزک اورا دیده، به حاضرین گفتن گرفت که «این شخص از آنها است!»"},{"v":70,"t":"او باز انکار کرد. و بعد از زمانی حاضرین بار دیگر به پطرس گفتند: «در حقیقت تو از آنها می‌باشی زیرا که جلیلی نیز هستی ولهجه تو چنان است.»"},{"v":71,"t":"پس به لعن کردن و قسم خوردن شروع نمود که «آن شخص را که می‌گویید نمی شناسم.»"},{"v":72,"t":"ناگاه خروس مرتبه دیگر بانگ زد. پس پطرس را به‌خاطر آمد آنچه عیسی بدو گفته بود که «قبل از آنکه خروس دومرتبه بانگ زند، سه مرتبه مرا انکار خواهی نمود.» و چون این را به‌خاطر آورد، بگریست."}]},"15":{"fa":[{"v":1,"t":"بامدادان، بی‌درنگ روسای کهنه بامشایخ و کاتبان و تمام اهل شورامشورت نمودند و عیسی را بند نهاده، بردند و به پیلاطس تسلیم کردند."},{"v":2,"t":"پیلاطس از او پرسید: «آیا تو پادشاه یهودهستی؟» او در جواب وی گفت: «تو می‌گویی.»"},{"v":3,"t":"و چون روسای کهنه ادعای بسیار بر او می نمودند،"},{"v":4,"t":"پیلاطس باز از او سوال کرده، گفت: «هیچ جواب نمی دهی؟ ببین که چقدر بر توشهادت می‌دهند!»"},{"v":5,"t":"اما عیسی باز هیچ جواب نداد، چنانکه پیلاطس متعجب شد."},{"v":6,"t":"و در هر عید یک زندانی، هر‌که رامی خواستند، بجهت ایشان آزاد می‌کرد."},{"v":7,"t":"و برابانامی با شرکای فتنه او که در فتنه خونریزی کرده بودند، در حبس بود."},{"v":8,"t":"آنگاه مردم صدازده، شروع کردند به‌خواستن که برحسب عادت با ایشان عمل نماید."},{"v":9,"t":"پیلاطس درجواب ایشان گفت: «آیا می‌خواهید پادشاه یهود را برای شما آزاد کنم؟»"},{"v":10,"t":"زیرا یافته بودکه روسای کهنه او را از راه حسد تسلیم کرده بودند."},{"v":11,"t":"اما روسای کهنه مردم را تحریض کرده بودند که بلکه برابا را برای ایشان رهاکند."},{"v":12,"t":"پیلاطس باز ایشان را در جواب گفت: «پس چه می‌خواهید بکنم با آن کس که پادشاه یهودش می‌گویید؟»"},{"v":13,"t":"ایشان بار دیگر فریادکردند که «او را مصلوب کن!»"},{"v":14,"t":"پیلاطس بدیشان گفت: «چرا؟ چه بدی کرده است؟» ایشان بیشتر فریاد برآوردند که «او را مصلوب کن.»"},{"v":15,"t":"پس پیلاطس چون خواست که مردم راخشنود گرداند، برابا را برای ایشان آزاد کرد وعیسی را تازیانه زده، تسلیم نمود تا مصلوب شود."},{"v":16,"t":"آنگاه سپاهیان او را به‌سرایی که دارالولایه است برده، تمام فوج را فراهم آوردند"},{"v":17,"t":"وجامه‌ای قرمز بر او پوشانیدند و تاجی از خاربافته، بر سرش گذاردند"},{"v":18,"t":"و او را سلام کردن گرفتند که «سلام‌ای پادشاه یهود!»"},{"v":19,"t":"و نی بر سراو زدند و آب دهان بر وی انداخته و زانو زده، بدو تعظیم می‌نمودند."},{"v":20,"t":"و چون او را استهزاکرده بودند، لباس قرمز را از وی کنده جامه خودش را پوشانیدند و او را بیرون بردند تامصلوبش سازند."},{"v":21,"t":"و راهگذری را شمعون نام، از اهل قیروان که از بلوکات می‌آمد، و پدر اسکندر و رفس بود، مجبور ساختند که صلیب او را بردارد."},{"v":22,"t":"پس اورا به موضعی که جلجتا نام داشت یعنی محل کاسه سر بردند"},{"v":23,"t":"و شراب مخلوط به مر به وی دادند تا بنوشد لیکن قبول نکرد."},{"v":24,"t":"و چون او رامصلوب کردند، لباس او را تقسیم نموده، قرعه برآن افکندند تا هر کس چه برد."},{"v":25,"t":"و ساعت سوم بود که اورا مصلوب کردند."},{"v":26,"t":"و تقصیر نامه وی این نوشته شد: «پادشاه یهود.»"},{"v":27,"t":"و با وی دو دزد را یکی از دست راست و دیگری از دست چپ مصلوب کردند."},{"v":28,"t":"پس تمام گشت آن نوشته‌ای که می‌گوید: «ازخطاکاران محسوب گشت.»"},{"v":29,"t":"و راهگذاران او رادشنام داده و سر خود را جنبانیده، می‌گفتند: «هان‌ای کسی‌که هیکل را خراب می‌کنی و در سه روز آن را بنا می‌کنی،"},{"v":30,"t":"از صلیب به زیرآمده، خود را برهان!»"},{"v":31,"t":"و همچنین روسای کهنه و کاتبان استهزاکنان با یکدیگر می‌گفتند؛ «دیگران را نجات داد و نمی تواند خود را نجات دهد."},{"v":32,"t":"مسیح، پادشاه اسرائیل، الان از صلیب نزول کند تا ببینیم و ایمان آوریم.» و آنانی که با وی مصلوب شدند او را دشنام می‌دادند."},{"v":33,"t":"و چون ساعت ششم رسید تا ساعت نهم تاریکی تمام زمین را فرو گرفت."},{"v":34,"t":"و در ساعت نهم، عیسی به آواز بلند ندا کرده، گفت: «ایلوئی ایلوئی، لما سبقتنی؟» یعنی «الهی الهی چرا مراواگذاردی؟»"},{"v":35,"t":"و بعضی از حاضرین چون شنیدند گفتند: «الیاس را می‌خواند.»"},{"v":36,"t":"پس شخصی دویده، اسفنجی را از سرکه پر کرد و برسر نی نهاده، بدو نوشانید و گفت: «بگذارید ببینیم مگر الیاس بیاید تا او را پایین آورد.»"},{"v":37,"t":"پس عیسی آوازی بلند برآورده، جان بداد."},{"v":38,"t":"آنگاه پرده هیکل از سر تا پا دوپاره شد."},{"v":39,"t":"و چون یوزباشی که مقابل وی ایستاده بود، دید که بدینطور صدا زده، روح را سپرد، گفت؛ «فی الواقع این مرد، پسر خدا بود.»"},{"v":40,"t":"و زنی چند از دور نظر می‌کردند که ازآنجمله مریم مجدلیه بود و مریم مادر یعقوب کوچک و مادر یوشا و سالومه،"},{"v":41,"t":"که هنگام بودن او در جلیل پیروی و خدمت او می‌کردند. و دیگرزنان بسیاری که به اورشلیم آمده بودند."},{"v":42,"t":"و چون شام شد، از آن جهت روز تهیه یعنی روز قبل از سبت بود،"},{"v":43,"t":"یوسف نامی ازاهل رامه که مرد شریف از اعضای شورا و نیزمنتظر ملکوت خدا بود آمد و جرات کرده نزدپیلاطس رفت و جسد عیسی را طلب نمود."},{"v":44,"t":"پیلاطس تعجب کرد که بدین زودی فوت شده باشد، پس یوزباشی را طلبیده، از او پرسید که «آیاچندی گذشته وفات نموده است؟»"},{"v":45,"t":"چون ازیوزباشی دریافت کرد، بدن را به یوسف ارزانی داشت."},{"v":46,"t":"پس کتانی خریده، آن را از صلیب به زیر آورد و به آن کتان کفن کرده، در قبری که ازسنگ تراشیده بود نهاد و سنگی بر سر قبرغلطانید."},{"v":47,"t":"و مریم مجدلیه و مریم مادر یوشادیدند که کجا گذاشته شد."}]},"16":{"fa":[{"v":1,"t":"پس چون سبت گذشته بود، مریم مجدلیه و مریم مادر یعقوب و سالومه حنوط خریده، آمدند تا او را تدهین کنند."},{"v":2,"t":"وصبح روز یکشنبه را بسیار زود وقت طلوع آفتاب بر سر قبر‌آمدند."},{"v":3,"t":"و با یکدیگر می‌گفتند: «کیست که سنگ را برای ما از سر قبر بغلطاند؟»"},{"v":4,"t":"چون نگریستند، دیدند که سنگ غلطانیده شده است زیرا بسیار بزرگ بود."},{"v":5,"t":"و چون به قبر درآمدند، جوانی را که جامه‌ای سفید دربرداشت بر جانب راست نشسته دیدند. پس متحیر شدند."},{"v":6,"t":"اوبدیشان گفت: «ترسان مباشید! عیسی ناصری مصلوب را می‌طلبید؟ او برخاسته است! در اینجانیست. آن موضعی را که او را نهاده بودند، ملاحظه کنید."},{"v":7,"t":"لیکن رفته، شاگردان او و پطرس را اطلاع دهید که پیش از شما به جلیل می‌رود. اورا در آنجا خواهید دید، چنانکه به شما فرموده بود.»"},{"v":8,"t":"پس بزودی بیرون شده از قبر گریختندزیرا لرزه و حیرت ایشان را فرو گرفته بود و به کسی هیچ نگفتند زیرا می‌ترسیدند."},{"v":9,"t":"و صبحگاهان، روز اول هفته چون برخاسته بود، نخستین به مریم مجدلیه که از او هفت دیوبیرون کرده بود ظاهر شد."},{"v":10,"t":"و او رفته اصحاب اورا که گریه و ماتم می‌کردند خبر داد."},{"v":11,"t":"و ایشان چون شنیدند که زنده گشته و بدو ظاهر شده بود، باور نکردند."},{"v":12,"t":"و بعد از آن به صورت دیگر به دو نفر ازایشان در هنگامی که به دهات می‌رفتند، هویداگردید."},{"v":13,"t":"ایشان رفته، دیگران را خبر دادند، لیکن ایشان را نیز تصدیق ننمودند."},{"v":14,"t":"و بعد از آن بدان یازده هنگامی که به غذانشسته بودند ظاهر شد و ایشان را به‌سبب بی‌ایمانی و سخت دلی ایشان توبیخ نمود زیرا به آنانی که او را برخاسته دیده بودند، تصدیق ننمودند."},{"v":15,"t":"پس بدیشان گفت: «در تمام عالم بروید وجمیع خلایق را به انجیل موعظه کنید."},{"v":16,"t":"هر‌که ایمان آورده، تعمید یابد نجات یابد و اما هر‌که ایمان نیاورد بر او حکم خواهد شد."},{"v":17,"t":"و این آیات همراه ایمانداران خواهد بود که به نام من دیوها را بیرون کنند و به زبانهای تازه حرف زنند"},{"v":18,"t":"و مارها را بردارند و اگر زهر قاتلی بخورندضرری بدیشان نرساند و هرگاه دستها بر مریضان گذارند شفا خواهند یافت.»"},{"v":19,"t":"و خداوند بعد از آنکه به ایشان سخن گفته بود، به سوی آسمان مرتفع شده، به‌دست راست خدا بنشست."},{"v":20,"t":"و ایشان بیرون رفته، در هر جاموعظه می‌کردند و خداوند با ایشان کار می‌کرد وبه آیاتی که همراه ایشان می‌بود، کلام را ثابت می‌گردانید."}]}});
